        name: team.name || team.color || (idx === 0 ? "blue" : "orange"),
        goals: Number(team.goals ?? team.stats?.core?.goals ?? 0) || 0,
        stats: liveReplaySafeObj(team.stats),
        players: Array.isArray(team.players)
