      teamGoals: numberStat(player.teamGoals ?? player.team?.goals ?? player.teamStats?.core?.goals, null),
      score: numberStat(core.score ?? player.score),
      goals: numberStat(core.goals ?? player.goals),
      assists: numberStat(core.assists ?? player.assists),
      saves: numberStat(core.saves ?? player.saves),
      shots: numberStat(core.shots ?? player.shots),
      shootingPercentage: numberStat(core.shooting_percentage ?? core.shootingPercentage, null),
      shotsAgainst: numberStat(core.shots_against, null),
      goalsAgainst: numberStat(core.goals_against, null),
      mvp: !!(core.mvp || player.mvp),
      boostCollected: numberStat(boost.amount_collected ?? boost.collected ?? boost.boost_collected, null),
      boostStolen: numberStat(boost.amount_stolen ?? boost.stolen ?? boost.boost_stolen, null),
      boostCollectedBig: numberStat(boost.amount_collected_big, null),
      boostStolenBig: numberStat(boost.amount_stolen_big, null),
      boostCollectedSmall: numberStat(boost.amount_collected_small, null),
      boostStolenSmall: numberStat(boost.amount_stolen_small, null),
      boostCountBig: numberStat(boost.count_collected_big, null),
      boostCountSmall: numberStat(boost.count_collected_small, null),
      boostCountStolenBig: numberStat(boost.count_stolen_big, null),
      boostCountStolenSmall: numberStat(boost.count_stolen_small, null),
      boostOverfill: numberStat(boost.amount_overfill, null),
      boostOverfillStolen: numberStat(boost.amount_overfill_stolen, null),
      boostUsedWhileSupersonic: numberStat(boost.amount_used_while_supersonic, null),
      avgBoost: numberStat(boost.avg_amount ?? boost.average_amount ?? boost.avg_boost, null),
      zeroBoostTime: numberStat(boost.time_zero_boost ?? boost.time_at_0_boost ?? boost.time_zero, null),
      zeroBoostPct: numberStat(boost.percent_zero_boost, null),
      fullBoostTime: numberStat(boost.time_full_boost, null),
      fullBoostPct: numberStat(boost.percent_full_boost, null),
      boostTime0_25: numberStat(boost.time_boost_0_25, null),
      boostTime25_50: numberStat(boost.time_boost_25_50, null),
      boostTime50_75: numberStat(boost.time_boost_50_75, null),
      boostTime75_100: numberStat(boost.time_boost_75_100, null),
      boostPct0_25: numberStat(boost.percent_boost_0_25, null),
      boostPct25_50: numberStat(boost.percent_boost_25_50, null),
