// ===================== Face ID / Touch ID login helpers =====================
function bbBase64UrlEncode(buffer) {
  const bytes = buffer instanceof Uint8Array ? buffer : new Uint8Array(buffer || []);
  let str = "";
  bytes.forEach(b => { str += String.fromCharCode(b); });
  return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}
function bbBase64UrlDecode(value = "") {
  const input = String(value || "").replace(/-/g, "+").replace(/_/g, "/");
  const padded = input + "=".repeat((4 - input.length % 4) % 4);
  const raw = atob(padded);
  const bytes = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
  return bytes;
}
function bbRandomChallenge(bytes = 32) {
  const arr = new Uint8Array(bytes);
  try { crypto.getRandomValues(arr); }
  catch (_) { for (let i=0;i<bytes;i++) arr[i] = Math.floor(Math.random()*255); }
  return arr;
}
function bbPlayerUserId(playerId = "") {
  const src = `burton-battlers:${playerId || "player"}`;
  const arr = new Uint8Array(32);
  for (let i = 0; i < src.length; i++) arr[i % 32] = (arr[i % 32] + src.charCodeAt(i) + i) % 255;
  return arr;
}
function biometricLabel() {
  const ua = typeof navigator !== "undefined" ? navigator.userAgent || "" : "";
  if (/iPhone|iPad|Mac/i.test(ua)) return "Face ID";
  if (/Android/i.test(ua)) return "biometric unlock";
  return "device unlock";
}
function canUseBiometricLogin() {
  try {
    return typeof window !== "undefined" &&
      !!window.PublicKeyCredential &&
      !!navigator?.credentials &&
      (window.isSecureContext || location.hostname === "localhost");
  } catch (_) {
    return false;
  }
}
async function enrollBiometricLoginForPlayer(player = {}) {
  if (!canUseBiometricLogin()) throw new Error(`${biometricLabel()} is not available in this browser.`);
  const credential = await navigator.credentials.create({
    publicKey: {
      challenge: bbRandomChallenge(),
      rp: { name: "Burton Battlers" },
      user: {
        id: bbPlayerUserId(player.id),
        name: player.name || player.id || "player",
        displayName: player.name || "Burton Battler",
      },
      pubKeyCredParams: [
        { type:"public-key", alg:-7 },
        { type:"public-key", alg:-257 },
      ],
      authenticatorSelection: {
        authenticatorAttachment: "platform",
        userVerification: "required",
        residentKey: "preferred",
      },
      timeout: 60000,
      attestation: "none",
    }
  });
  if (!credential?.rawId) throw new Error(`${biometricLabel()} setup was cancelled.`);
  return {
    enabled:true,
    credentialId: bbBase64UrlEncode(credential.rawId),
    credentialType: credential.type || "public-key",
    setupAt: new Date().toISOString(),
  };
}
async function unlockWithBiometricForPlayer(player = {}, auth = {}) {
  const credentialId = auth?.biometricCredentialId || auth?.biometric?.credentialId;
  if (!credentialId) throw new Error(`${biometricLabel()} is not set up for ${player?.name || "this user"}.`);
  if (!canUseBiometricLogin()) throw new Error(`${biometricLabel()} is not available in this browser.`);
  const assertion = await navigator.credentials.get({
    publicKey: {
      challenge: bbRandomChallenge(),
      allowCredentials: [{ type:"public-key", id: bbBase64UrlDecode(credentialId) }],
      userVerification: "required",
      timeout: 60000,
    }
  });
  if (!assertion) throw new Error(`${biometricLabel()} unlock was cancelled.`);
  return true;
}


// ===================== Auth screens =====================
function NameSelectScreen({ onSelect }) {
  return (
    <div style={{...s.loginScreen, animation:"fadeSlideUp .22s cubic-bezier(.2,.8,.2,1)"}}>
      <div style={s.loginGlow} />
      <div style={s.loginContent}>
        <div style={s.loginEyebrow}>rivalry circuit · jul 20 – sep 21</div>
        <div style={s.loginTitle}>the burton<br/>battlers</div>
        <div style={s.loginSub}>who's logging in?</div>
        <div style={s.loginPlayerGrid}>
          {PLAYERS.map((p) => (
            <button key={p.id} onClick={() => onSelect(p.id)} className="bb-pressable" style={s.loginPlayerBtn}>
              <div style={{ ...s.loginPlayerDot, background:p.color, boxShadow:`0 0 10px ${p.color}99` }} />
              {p.name}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

function CreatePasscodeScreen({ player, onCreated }) {
  const [code, setCode] = useState(""); const [confirm, setConfirm] = useState(""); const [error, setError] = useState("");
  const submit = async () => {
    if (code.length < 4) return setError("Use at least 4 digits.");
    if (code !== confirm) return setError("Codes don't match.");
    const nextAuth = { passcode: code };
    await storeSet(`auth:${player.id}`, nextAuth);
    if (canUseBiometricLogin()) {
      try {
        setError(`Setting up ${biometricLabel()}…`);
        const bio = await enrollBiometricLoginForPlayer(player);
        await storeSet(`auth:${player.id}`, { ...nextAuth, biometricCredentialId:bio.credentialId, biometricEnabled:true, biometricSetupAt:bio.setupAt });
      } catch (_) {
        // Passcode remains the fallback if biometric setup is cancelled or unavailable.
      }
    }
    onCreated();
  };
  return (
   <div style={{...s.loginScreen, animation:"fadeSlideUp .22s cubic-bezier(.2,.8,.2,1)"}}><div style={s.loginGlow} /><div style={s.loginContent}>
      <div style={{ ...s.loginPlayerDot, background:player.color, margin:"0 auto 18px", width:14, height:14 }} />
      <div style={s.loginTitle}>{player.name}</div>
      <div style={s.loginSub}>create your passcode</div>
      <div style={s.loginCodeWrap}>
        <input type="password" inputMode="numeric" value={code} onChange={(e)=>setCode(e.target.value)} placeholder="NEW PASSCODE" style={s.loginInput} autoFocus />
        <input type="password" inputMode="numeric" value={confirm} onChange={(e)=>setConfirm(e.target.value)} onKeyDown={(e)=>e.key==="Enter"&&submit()} placeholder="CONFIRM PASSCODE" style={s.loginInput} />
        {error && <div style={s.loginError}>{error}</div>}
    <button onClick={submit} className="bb-pressable bb-glow-lime" style={s.loginSubmit}>set passcode <ChevronRight size={16}/></button>
      </div>
    </div></div>
  );
}
function EnterPasscodeScreen({ player, onSuccess, onBack, onAdmin }) {
  const [code, setCode] = useState("");
  const [error, setError] = useState("");
  const [shaking, setShaking] = useState(false);
  const [adminMode, setAdminMode] = useState(false);
  const [bioStatus, setBioStatus] = useState("");
  const [bioBusy, setBioBusy] = useState(false);
  const [bioGate, setBioGate] = useState("checking"); // checking -> prompting -> fallback
  const cachedAuth = useRef(null);
  const bioTried = useRef(false);
  const unlockStarted = useRef(false);

  const setupBiometricAfterPasscode = async (authObj = {}) => {
    if (adminMode || authObj?.biometricCredentialId || authObj?.biometricEnabled === false || !canUseBiometricLogin()) return;
    try {
      setBioStatus(`Setting up ${biometricLabel()}…`);
      const bio = await enrollBiometricLoginForPlayer(player);
      const nextAuth = { ...(authObj || {}), passcode:authObj?.passcode || code, biometricCredentialId:bio.credentialId, biometricEnabled:true, biometricSetupAt:bio.setupAt };
      await storeSet(`auth:${player.id}`, nextAuth);
      cachedAuth.current = nextAuth;
      setBioStatus(`${biometricLabel()} ready for next login`);
    } catch (_) {
      setBioStatus(`${biometricLabel()} skipped. Passcode still works.`);
    }
  };

  const finishUnlock = (finalCode = "") => {
    if (unlockStarted.current) return;
    unlockStarted.current = true;
    setError("");
    setCode(finalCode);
    setTimeout(() => {
      if (adminMode && onAdmin) onAdmin();
      else onSuccess();
    }, 0);
  };

  const revealPasscodeFallback = (msg = "") => {
    setBioGate("fallback");
    if (msg) setBioStatus(msg);
  };

  const tryBiometricUnlock = async (authObj = cachedAuth.current, manual = false) => {
    if (adminMode) return revealPasscodeFallback("");
    if (!authObj?.biometricCredentialId) {
      return revealPasscodeFallback(canUseBiometricLogin() ? `Enter passcode once to set up ${biometricLabel()}.` : "");
    }
    if (bioBusy || unlockStarted.current) return;
    setBioBusy(true);
    setBioGate("prompting");
    setBioStatus(`Scanning ${biometricLabel()}…`);
    try {
      await unlockWithBiometricForPlayer(player, authObj);
      setBioStatus(`${biometricLabel()} accepted`);
      finishUnlock("");
    } catch (_) {
      revealPasscodeFallback(`${biometricLabel()} failed or was cancelled. Passcode is ready below.`);
      if (manual) setError(`${biometricLabel()} failed. Use passcode.`);
    } finally {
      setBioBusy(false);
    }
  };

  useEffect(() => {
    let alive = true;
    bioTried.current = false;
    unlockStarted.current = false;
    setBioStatus("");
    setBioGate("checking");

    const fallbackTimer = setTimeout(() => {
      if (!alive || unlockStarted.current || bioTried.current) return;
      revealPasscodeFallback("");
    }, 850);

    Promise.resolve(storeGet(`auth:${player.id}`))
      .then(a => {
        if (!alive) return;
        clearTimeout(fallbackTimer);
        cachedAuth.current = a;
        if (a?.biometricCredentialId) {
          bioTried.current = true;
          tryBiometricUnlock(a, false);
        } else {
          revealPasscodeFallback(canUseBiometricLogin() ? `Enter passcode once to set up ${biometricLabel()}.` : "");
        }
      })
      .catch(() => {
        if (!alive) return;
        clearTimeout(fallbackTimer);
        revealPasscodeFallback("");
      });
    return () => { alive = false; clearTimeout(fallbackTimer); };
  }, [player.id]);

  const submit = (finalCode) => {
    const cached = cachedAuth.current;
    if (cached?.passcode && cached.passcode !== finalCode) {
      setShaking(true);
      setError("Wrong passcode.");
      setCode("");
      setTimeout(() => setShaking(false), 360);
      return;
    }

    Promise.resolve(storeGet(`auth:${player.id}`))
      .then(async a => {
        const authObj = a || cached || { passcode:finalCode };
        cachedAuth.current = authObj;
        if (!authObj?.passcode) {
          const next = { ...authObj, passcode:finalCode };
          cachedAuth.current = next;
          await storeSet(`auth:${player.id}`, next).catch(() => {});
        }
        await setupBiometricAfterPasscode(cachedAuth.current).catch(() => {});
      })
      .catch(() => {})
      .finally(() => finishUnlock(finalCode));
  };

  const pressNum = (num) => {
    if (code.length >= 4) return;
    const next = code + num;
    setCode(next);
    setError("");
    if (next.length === 4) setTimeout(() => submit(next), 80);
  };

  const pressDelete = () => setCode(c => c.slice(0, -1));

  const NUMS = [["1","2","3"],["4","5","6"],["7","8","9"],["","0","⌫"]];

  if (!adminMode && bioGate !== "fallback") {
    return (
      <div style={{...s.loginScreen,background:"#000",animation:"fadeSlideUp .12s ease"}}>
        <div style={{position:"absolute",inset:0,background:"radial-gradient(circle at 50% 18%, rgba(184,255,77,.10), transparent 38%), #000"}} />
        <button onClick={onBack} className="bb-pressable" style={{position:"fixed",top:"max(16px, env(safe-area-inset-top))",left:16,zIndex:5,background:"rgba(255,255,255,.05)",border:"1px solid rgba(255,255,255,.08)",borderRadius:999,padding:"9px 12px",color:"#8B92A8",fontSize:11,fontWeight:900,cursor:"pointer",display:"flex",alignItems:"center",gap:6}}><ChevronLeft size={14}/> back</button>
        <div style={{position:"relative",zIndex:2,minHeight:"100dvh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,textAlign:"center"}}>
          <div style={{width:82,height:82,borderRadius:28,border:`1px solid ${player.color}55`,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 0 34px ${player.color}24`,marginBottom:18}}>
            <div style={{width:46,height:46,borderRadius:16,border:`2px solid ${player.color}`,boxShadow:`0 0 18px ${player.color}55`}} />
          </div>
          <div style={{fontSize:10,color:player.color,fontWeight:950,letterSpacing:1.4,textTransform:"uppercase",marginBottom:7}}>{player.name}</div>
          <div style={{fontFamily:"'Oswald',sans-serif",fontSize:30,fontWeight:700,color:"#E8ECF4",lineHeight:1,textTransform:"lowercase"}}>
            {bioGate === "checking" ? "preparing unlock" : `use ${biometricLabel()}`}
          </div>
          <div style={{fontSize:11,color:"#8B92A8",fontWeight:800,lineHeight:1.45,marginTop:10,maxWidth:280}}>
            {bioGate === "checking" ? "Checking saved unlock…" : "The device prompt should appear now. If it fails, passcode opens automatically."}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={s.loginScreen}>
      <div style={s.loginGlow} />
      <div style={s.loginContent}>
        <button onClick={onBack} className="bb-pressable" style={s.backBtn}><ChevronLeft size={16}/> back</button>
        <div style={{ ...s.loginPlayerDot, background:player.color, margin:"0 auto 18px", width:14, height:14 }} />
        <div style={s.loginTitle}>{player.name}</div>
        <div style={s.loginSub}>{adminMode ? "admin passcode" : "passcode fallback"}</div>
        {bioStatus && !adminMode && <div style={{fontSize:10.5,color:"#8B92A8",fontWeight:800,lineHeight:1.35,textAlign:"center",margin:"10px 0 16px"}}>{bioStatus}</div>}
        <div style={{display:"flex",justifyContent:"center",gap:16,marginBottom:32,marginTop:8}}>
          {[0,1,2,3].map(i => (
            <div key={i} style={{width:14,height:14,borderRadius:"50%",background:code.length>i?player.color:"rgba(255,255,255,0.15)",transition:"background .15s ease",boxShadow:code.length>i?`0 0 8px ${player.color}99`:""}}/>
          ))}
        </div>
        {error && <div style={{...s.loginError,marginBottom:16,textAlign:"center"}}>{error}</div>}
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {NUMS.map((row, ri) => (
            <div key={ri} style={{display:"flex",justifyContent:"center",gap:20}}>
              {row.map((num, ci) => (
                num === "" ? <div key={ci} style={{width:72,height:72}}/> :
                <button key={ci} onClick={() => { num==="⌫" ? pressDelete() : pressNum(num); }}
                  className="bb-pressable"
                  style={{width:72,height:72,borderRadius:"50%",background:num==="⌫"?"none":"rgba(255,255,255,0.08)",border:num==="⌫"?"none":"1px solid rgba(255,255,255,0.1)",color:"#E8ECF4",fontSize:num==="⌫"?22:24,fontWeight:600,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>
                  {num}
                </button>
              ))}
            </div>
          ))}
        </div>
        {player?.id === ADMIN_ID && onAdmin && (
          <button onClick={()=>{ setAdminMode(true); setCode(""); setError(""); setBioStatus(""); setBioGate("fallback"); }} className="bb-pressable" style={{marginTop:18,background:adminMode?"rgba(255,92,138,0.18)":"rgba(255,92,138,0.10)",border:"1px solid rgba(255,92,138,0.28)",borderRadius:12,padding:"10px 14px",fontSize:12,fontWeight:900,color:"#FF5C8A",cursor:"pointer"}}>
            {adminMode ? "type passcode for admin" : "admin controls"}
          </button>
        )}
      </div>
    </div>
  );
}

function TrackerSetup({ player, onComplete, onUseCredit }) {
  const [syncing, setSyncing] = useState(false);
  const [error, setError] = useState(null);

  const finishSync = async () => {
    if (onUseCredit) {
      const ok = await onUseCredit();
      if (!ok) { setError("out of parse credits — ask the captain for more"); return; }
    }
    setSyncing(true);
    setError(null);
    try {
      const res = await fetch(
       `https://api.parse.bot/scraper/d0dcf8e8-3a72-4b21-bffb-8fa735257835/get_player_profile?platform=${encodeURIComponent(player.platform)}&username=${encodeURIComponent(player.name)}`,
        { headers: { "X-API-Key": PARSE_API_KEY } }
      );
      if (!res.ok) throw new Error(`profile sync returned ${res.status}`);
      const json = await res.json();
      if (json?.status && json.status !== "success") throw new Error(json?.message || "profile sync failed");
      const segments = json?.data?.segments || [];
      const playlistIds = { "Ranked Duel 1v1": 10, "Ranked Doubles 2v2": 11, "Ranked Standard 3v3": 13 };
      const ranks = RL_PLAYLISTS.map(name => {
     const seg = segments.find(s => s.type === "playlist" && s.metadata?.name === name);
const mmr = seg?.stats?.rating?.value || 0;

console.log("MMR SEGMENT:", name, seg?.stats);

const rankInfo = getRankInfoFromSegment(seg, { rank: "Unranked", division: "", playlist: name, playerName: player.name });

return { playlist: name, mmr, rank: rankInfo.rank, division: rankInfo.division };
});

console.log("FINAL RANKS BEING SAVED:", ranks);

await setMMR(player.id, { platform: player.platform, handle: player.name, ranks, lastSynced: new Date().toISOString(), source: "synced" });
      setSyncing(false);
      onComplete();
    } catch (e) {
      setError("failed to fetch — check connection");
      setSyncing(false);
    }
  };

  return (
    <div style={s.screen}>
      <div style={s.setupWrap}>
        <div style={s.setupTitle}>link your rocket league account</div>
        <div style={s.setupSub}>pulls your real ranks from tracker.gg</div>
        <div style={{ marginBottom: 16, background: "#11131F", borderRadius: 14, padding: 14, border: "1px solid rgba(255,255,255,0.06)" }}>
          <div style={{ fontSize: 11, color: "#4A5066", marginBottom: 4 }}>platform</div>
          <div style={{ fontSize: 14, fontWeight: 700, color: "#B8FF4D" }}>{player.platform.toUpperCase()}</div>
          <div style={{ fontSize: 11, color: "#4A5066", marginTop: 8, marginBottom: 4 }}>username</div>
          <div style={{ fontSize: 14, fontWeight: 700, color: "#E8ECF4" }}>{player.name}</div>
        </div>
        {error && <div style={{ color: "#FF5C8A", fontSize: 12, marginBottom: 12 }}>{error}</div>}
        <button onClick={finishSync} disabled={syncing} className="bb-pressable bb-glow-lime" style={{ ...s.primaryBtn, opacity: syncing ? 0.6 : 1 }}>
          {syncing ? "fetching from tracker…" : "sync my ranks"}
        </button>
      </div>
    </div>
  );
}

