const REACTION_EMOJIS = ["🐐","💩","😕","🤓","🌬️","🥀","🤣","😎","🫩","😭","🙉","😈"];
function seededShuffle(arr, seed) {
  const out = [...arr];
  for (let i = out.length - 1; i > 0; i--) {
    seed = (seed * 1664525 + 1013904223) & 0xffffffff;
    const j = Math.abs(seed) % (i + 1);
    [out[i], out[j]] = [out[j], out[i]];
  }
  return out;
}
          
