function TokenDetailModal({ token, currentPlayer, passTokens, setPassTokens, activeBoost, onClose }) {
  const [activating, setActivating] = useState(false);
  const isDoubleXp = token.type === "double_xp";
  const alreadyActive = activeBoost && activeBoost.type === "double_xp" && Date.now() < new Date(activeBoost.expiresAt).getTime();
  const [remaining, setRemaining] = useState(0);

  useEffect(() => {
    if (!alreadyActive) return;
    const iv = setInterval(() => {
      setRemaining(Math.max(0, new Date(activeBoost.expiresAt).getTime() - Date.now()));
    }, 1000);
    return () => clearInterval(iv);
  }, [alreadyActive, activeBoost]);

  const fmtRemaining = (ms) => {
    const h = Math.floor(ms / 3600000);
    const m = Math.floor((ms % 3600000) / 60000);
    const sec = Math.floor((ms % 60000) / 1000);
    return `${h}h ${m}m ${sec}s`;
  };

  const activate = async () => {
    if (alreadyActive || activating) return;
    setActivating(true);
    const now = Date.now();
    const expiresAt = new Date(now + DOUBLE_XP_DURATION_MS).toISOString();
    const activeBoosts = await storeGet("pass_active_boosts") || {};
    const updBoosts = { ...activeBoosts, [currentPlayer]: { type: token.type, label: token.label, activatedAt: new Date(now).toISOString(), expiresAt } };
    await storeSet("pass_active_boosts", updBoosts);
    // consume the token (one-time use)
    const myTokens = passTokens?.[currentPlayer] || [];
    const updTokens = { ...passTokens, [currentPlayer]: myTokens.filter(t => t.id !== token.id) };
    setPassTokens(updTokens);
    await storeSet("pass_tokens", updTokens);
    setActivating(false);
    onClose();
  };

  return (
    <div style={s.modalOverlay} onClick={onClose}>
      <div style={s.modalBox} onClick={(e) => e.stopPropagation()}>
        <div style={s.modalHeader}>
          <div style={s.modalTitle}>🎟 {token.label}</div>
          <button onClick={onClose} className="bb-pressable" style={s.modalClose}><X size={20} /></button>
        </div>
        {isDoubleXp ? (
          <>
            <div style={{ fontSize: 13.5, color: "#A8B2C4", lineHeight: 1.5, marginBottom: 16 }}>
              activating this doubles all your battle pass xp — training approvals (+20 → +40) and logged games (+15 → +30) — for the next 24 hours. one-time use.
            </div>
            {alreadyActive ? (
              <>
                <div style={{ background: "rgba(167,139,250,0.1)", border: "1px solid rgba(167,139,250,0.3)", borderRadius: 12, padding: 14, textAlign: "center", marginBottom: 10 }}>
                  <div style={{ fontSize: 11, color: "#A78BFA", fontWeight: 700, marginBottom: 6 }}>DOUBLE XP ALREADY ACTIVE</div>
                  <div style={{ fontFamily: "'Oswald',sans-serif", fontSize: 20, fontWeight: 700, color: "#E8ECF4" }}>{fmtRemaining(remaining)}</div>
                  <div style={{ fontSize: 10.5, color: "#4A5066", marginTop: 4 }}>remaining</div>
                </div>
                <div style={{ fontSize: 11.5, color: "#4A5066", textAlign: "center" }}>this token is still in your inventory — use it after your current boost ends.</div>
              </>
            ) : (
              <button onClick={activate} disabled={activating} className="bb-pressable bb-glow-violet" style={{ width: "100%", background: "#A78BFA", color: "#06070D", border: "none", borderRadius: 12, padding: 14, fontSize: 13.5, fontWeight: 700, cursor: "pointer", opacity: activating ? 0.6 : 1 }}>
                {activating ? "activating…" : "activate double xp — 24h"}
              </button>
            )}
          </>
        ) : (
          <div style={{ fontSize: 13.5, color: "#A8B2C4", lineHeight: 1.5 }}>
            {token.type === "training_skip" ? "use this to skip a single assigned training session without it counting against you — show this to your captain." : token.type === "coaching_session" ? "redeem this with your captain for a 1-on-1 coaching session." : "a reward token earned from the battle pass."}
          </div>
        )}
      </div>
    </div>
  );
}
function StarfieldBg() {
  // Keep moon-mode stars visible, but render fewer dots so CPU saver still helps battery.
  const stars = Array.from({length:42},(_,i)=>({
    x: (i*137.5)%100, y: (i*97.3)%100,
    r: i%5===0?1.5:i%3===0?1:0.6,
    op: 0.3+((i*73)%100)/200,
    dur: 2+(i%4),
  }));
  return (
    <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:0,overflow:"hidden"}}>
      {stars.map((st,i)=>(
        <div key={i} style={{position:"absolute",left:`${st.x}%`,top:`${st.y}%`,width:st.r*2,height:st.r*2,borderRadius:"50%",background:"#7EB8FF",opacity:st.op,animation:`livePulse ${st.dur}s ease-in-out infinite`,animationDelay:`${(i*0.3)%3}s`}}/>
      ))}
    </div>
  );
}
function SeasonalTextKitFx({ kitValue }) {
  if (BB_CPU_SAVER_MODE) return null;
  if (kitValue !== "fall" && kitValue !== "winter") return null;
  if (kitValue === "fall") {
    const leaves = Array.from({ length: 18 }, (_, i) => ({
      left: (i * 31 + 7) % 100,
      delay: (i * 1.9) % 11,
      dur: 15 + (i % 7),
      drift: ((i % 2 ? -1 : 1) * (22 + (i * 9) % 44)),
      leaf: i % 3 === 0 ? "🍁" : "🍂",
      size: 13 + (i % 5),
      opacity: 0.18 + ((i * 17) % 20) / 100,
    }));
    return (
      <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:1,overflow:"hidden"}}>
        {leaves.map((leaf, i)=>(
          <span key={i} style={{position:"absolute",left:`${leaf.left}%`,top:"-12vh",fontSize:leaf.size,opacity:leaf.opacity,filter:"blur(.15px)",animation:`bbLeafFall ${leaf.dur}s linear infinite`,animationDelay:`${leaf.delay}s`,"--bb-drift":`${leaf.drift}px`}}>{leaf.leaf}</span>
        ))}
      </div>
    );
  }
  const flakes = Array.from({ length: 44 }, (_, i) => ({
    left: (i * 19 + 5) % 100,
    delay: (i * 0.85) % 8,
    dur: 9 + (i % 9),
    drift: ((i % 2 ? -1 : 1) * (8 + (i * 5) % 28)),
    size: 2 + (i % 4),
    opacity: 0.28 + ((i * 11) % 35) / 100,
  }));
  return (
    <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:1,overflow:"hidden"}}>
      {flakes.map((flake, i)=>(
        <span key={i} style={{position:"absolute",left:`${flake.left}%`,top:"-10vh",width:flake.size,height:flake.size,borderRadius:"50%",background:"rgba(240,250,255,.94)",boxShadow:"0 0 8px rgba(159,216,255,.38)",opacity:flake.opacity,animation:`bbSnowFall ${flake.dur}s linear infinite`,animationDelay:`${flake.delay}s`,"--bb-drift":`${flake.drift}px`}}/>
      ))}
    </div>
  );
}
// ===================== Main App =====================
// Keys to subscribe to for real-time updates
// RLCS realtime keys must be declared before RT_KEYS so local dev does not crash.
const RLCS_ACTIVITY_FEED_KEY = "rlcs_activity_feed";
const RLCS_PRESENCE_KEY = "rlcs_live_presence";

const RT_KEYS = ["chat", "posts", "completions", "training", "schedule", "comments", "stream_profiles", "stats", "presence", "pings", "points", "bets", "pass_xp", "pass_premium", "pass_claimed", "pass_tokens", "pass_active_boosts", "time_logs", "stocks", "coin_flips", "active_race", "flowers","flip_challenges", "chemistry", "team_room", "team_sessions", "typing", "activity_feed", "parse_credits", "credit_requests", "push_subscriptions", "soundboard_events", "admin_shop_items", "full_screen_float_mode", "app_customizer", "burton_os", RLCS_ACTIVITY_FEED_KEY, RLCS_PRESENCE_KEY, ADMIN_LIVE_SYNC_KEY];
// Keep realtime on only the keys that need to feel instant. The full RT_KEYS list still exists
// for reference/hydration, but subscribing to every slow-changing key was making Supabase work too hard.
const RT_KEYS_LIVE = [
  // APP138: keep only instant gameplay/chat/session keys live.
  // Slow admin/shop/credits/notification feeds hydrate on boot or update through explicit writes, cutting Supabase realtime load.
  "chat", "stats", "points", "bets", "presence",
  "team_room", "team_sessions", "live_session", "typing",
  ADMIN_LIVE_SYNC_KEY
];
const BOOT_LIVE_DELAY_MS = 2500;
const BOOT_SECONDARY_HYDRATE_DELAY_MS = 3200;
const BOOT_MMR_HYDRATE_DELAY_MS = 9000;
const BOOT_BACKGROUND_EFFECT_DELAY_MS = 3500;
// APP120: disable in-app notification/toast UI and dropdown hydration. Phone/native push paths still run through storeSetWithPush/showLocalNotification.
const APP_IN_APP_NOTIFICATIONS_ENABLED = false;

// APP138_CPU_SUPABASE_LIGHT_CHAT_ANIMATION_PATCH
// Keep the app cooler on phones by reducing background writes/reads while keeping the important live pieces instant.
const BB_CPU_SAVER_MODE = true;
const BB_BACKGROUND_WRITE_DELAY_MS = 900;
const BB_BACKGROUND_WRITE_MIN_MS = 45000;
const CHAT_PANEL_CLOSE_MS = 260;
const BB_BACKGROUND_WRITE_CACHE = new Map();
const BB_BACKGROUND_WRITE_TIMERS = new Map();
const BB_BACKGROUND_WRITE_LAST_AT = new Map();

function storeSetBackground(key, value, { delayMs = BB_BACKGROUND_WRITE_DELAY_MS, minIntervalMs = BB_BACKGROUND_WRITE_MIN_MS } = {}) {
  const snapshot = bbStableStorageString(value);
  if (BB_BACKGROUND_WRITE_CACHE.get(key) === snapshot) return Promise.resolve(false);
  BB_BACKGROUND_WRITE_CACHE.set(key, snapshot);
  const now = Date.now();
  const lastAt = BB_BACKGROUND_WRITE_LAST_AT.get(key) || 0;
  const wait = Math.max(delayMs, minIntervalMs - (now - lastAt), 0);
  clearTimeout(BB_BACKGROUND_WRITE_TIMERS.get(key));
  return new Promise(resolve => {
    const timer = setTimeout(async () => {
      BB_BACKGROUND_WRITE_TIMERS.delete(key);
      BB_BACKGROUND_WRITE_LAST_AT.set(key, Date.now());
      try {
        await storeSet(key, value);
        resolve(true);
      } catch (_) {
        resolve(false);
      }
    }, wait);
    BB_BACKGROUND_WRITE_TIMERS.set(key, timer);
  });
}

// ===================== One-time manual restore =====================
const MANUAL_RESTORE_PATCH_ID = "manual_restore_20260630_points_pass_v1";
const MANUAL_RESTORE_POINTS = { p1:107, p2:700, p3:320 };
const MANUAL_RESTORE_XP = 402;
const MANUAL_RESTORE_PLAYERS = ["p1", "p2", "p3"];

function passOwnedRewardIdsFor(track, maxTier) {
  const rewards = track === "free" ? FREE_PASS_REWARDS : PREMIUM_PASS_REWARDS;
  return Array.from({ length:maxTier }, (_, i) => i + 1)
    .filter(tier => {
      const reward = rewards?.[tier];
      return ["color", "icon", "title", "text_color", "car"].includes(reward?.type);
    })
    .map(tier => `pass_${track}_${tier}`);
}

function buildManualRestoreState(existing = {}) {
  const currentPoints = existing.points && typeof existing.points === "object" ? existing.points : {};
  const currentClaimed = existing.passClaimed && typeof existing.passClaimed === "object" ? existing.passClaimed : {};
  const currentTokens = existing.passTokens && typeof existing.passTokens === "object" ? existing.passTokens : {};
  const currentXP = existing.passXP && typeof existing.passXP === "object" ? existing.passXP : {};
  const currentPremium = existing.passPremium && typeof existing.passPremium === "object" ? existing.passPremium : {};

  const passOwnedIds = Array.from(new Set([
    ...passOwnedRewardIdsFor("free", 4),
    ...passOwnedRewardIdsFor("premium", 14),
  ]));

  const restoredPoints = { ...currentPoints };
  Object.entries(MANUAL_RESTORE_POINTS).forEach(([pid, amount]) => {
    restoredPoints[pid] = Math.max(Number(currentPoints[pid]) || 0, Number(amount) || 0);
  });
  const restoredPassXP = { ...currentXP };
  const restoredPassPremium = { ...currentPremium };
  const restoredPassClaimed = { ...currentClaimed };
  const restoredPassTokens = { ...currentTokens };
  const restoredPassActiveBoosts = existing.passActiveBoosts && typeof existing.passActiveBoosts === "object" ? { ...existing.passActiveBoosts } : {};
  const now = new Date().toISOString();

  MANUAL_RESTORE_PLAYERS.forEach(pid => {
    restoredPassXP[pid] = Math.max(Number(restoredPassXP[pid]) || 0, MANUAL_RESTORE_XP);
    restoredPassPremium[pid] = true;

    for (let tier = 1; tier <= 4; tier++) restoredPassClaimed[`${pid}_free_${tier}`] = true;
    for (let tier = 1; tier <= 14; tier++) restoredPassClaimed[`${pid}_premium_${tier}`] = true;

    const owned = Array.isArray(currentPoints[pid + "_owned"]) ? currentPoints[pid + "_owned"] : [];
    restoredPoints[pid + "_owned"] = Array.from(new Set([...owned, ...passOwnedIds, ...DEFAULT_SOUNDBOARD_IDS]));
    const equipped = currentPoints[pid + "_equipped"] && typeof currentPoints[pid + "_equipped"] === "object" ? currentPoints[pid + "_equipped"] : {};
    restoredPoints[pid + "_equipped"] = { ...equipped };

    const tokens = Array.isArray(currentTokens[pid]) ? currentTokens[pid] : [];
    const hasPremium8Token = tokens.some(t => t?.restoreKey === "premium_8_double_xp" || (t?.type === "double_xp" && t?.label === "double xp token"));
    restoredPassTokens[pid] = hasPremium8Token ? tokens : [
      ...tokens,
      { id:`restore_${pid}_premium_8_${Date.now()}`, restoreKey:"premium_8_double_xp", type:"double_xp", label:"double xp token", earnedAt:now },
    ];
  });


  return { restoredPoints, restoredPassXP, restoredPassPremium, restoredPassClaimed, restoredPassTokens, restoredPassActiveBoosts };
}

// ===================== One-time inventory/equips restore =====================
const INVENTORY_RESTORE_PATCH_ID = "manual_restore_20260630_inventory_equips_v2";
const MAKEUP_SHOP_ITEM_IDS = [
  "gold_name", "teal_name", "violet_name", "blue_name",
  "icon_goat", "icon_crown", "icon_alien", "icon_bolt", "frog",
  "title_petty", "title_demogod", "title_lonely", "title_buffalo", "title_powershot",
  "sb_airhorn", "sb_sheesh", "sb_nice", "sb_bruh", "sb_pop", "sb_goal", "sb_laugh", "sb_buzzer",
  "bg_nebula", "bg_vapor", "bg_gold", "bg_void"
];
const PLAYER_RESTORE_EQUIPS = {
  p1: { icon:"icon_goat", title:"title_petty" },
  p2: { icon:"pass_premium_12", title:"title_demogod" },
  p3: { icon:"frog", title:"title_lonely" },
};
function getRestoreItemType(id) {
  const shop = getAllShopItems().find(i => i.id === id);
  if (shop) return shop.type;
  if (String(id || "").startsWith("pass_")) return getPassRewardForOwnedId(id)?.type || null;
  return null;
}
function buildInventoryRestoreState(pointsObj = {}) {
  const restoredPoints = pointsObj && typeof pointsObj === "object" ? { ...pointsObj } : {};
  PLAYERS.forEach(player => {
    const pid = player.id;
    const currentOwned = Array.isArray(restoredPoints[pid + "_owned"]) ? restoredPoints[pid + "_owned"] : [];
    const equipPlan = PLAYER_RESTORE_EQUIPS[pid] || {};
    const ownedAdditions = Array.from(new Set([
      ...MAKEUP_SHOP_ITEM_IDS,
      ...DEFAULT_SOUNDBOARD_IDS,
      equipPlan.icon,
      equipPlan.title,
    ].filter(Boolean)));
    const owned = Array.from(new Set([...currentOwned, ...ownedAdditions]));
    const equipped = restoredPoints[pid + "_equipped"] && typeof restoredPoints[pid + "_equipped"] === "object" ? { ...restoredPoints[pid + "_equipped"] } : {};

    // Only one visible icon/title should be active in presence, so clear those types first.
    owned.forEach(id => {
      const type = getRestoreItemType(id);
      if (type === "icon" || type === "title") delete equipped[id];
    });
    if (equipPlan.icon) equipped[equipPlan.icon] = true;
    if (equipPlan.title) equipped[equipPlan.title] = true;

    // Keep the default board ready and restore a few extra sound options without forcing every sound on.
    DEFAULT_SOUNDBOARD_IDS.forEach(id => { equipped[id] = true; });

    restoredPoints[pid + "_owned"] = owned;
    restoredPoints[pid + "_equipped"] = equipped;
  });
  return restoredPoints;
}

// ===================== Push Notifications =====================
const VAPID_PUBLIC_KEY = "BBdG7zPhz_GKE4gmJLC68Lp1vyAQB0TRK9XXy2ea91tiQCevbEiR1WFW-xHoLfVQjo3QEsdf5QfZP-kFk6XfEiE";
const PUSH_SUBSCRIPTIONS_KEY = "push_subscriptions";

function makeNotificationUrl(action, params = {}) {
  try {
    const qs = new URLSearchParams({ bb_action: String(action || "home") });
    Object.entries(params || {}).forEach(([k, v]) => {
      if (v === undefined || v === null || v === "") return;
      qs.set(k, String(v));
    });
    return `/?${qs.toString()}`;
  } catch (_) {
    return "/";
  }
}

function readNotificationDeepLink() {
  if (typeof window === "undefined") return null;
  try {
    const params = new URLSearchParams(window.location.search || "");
    const hashParams = new URLSearchParams(String(window.location.hash || "").replace(/^#\??/, ""));
    const action = params.get("bb_action") || hashParams.get("bb_action");
    if (!action) return null;
    const read = (key) => params.get(key) || hashParams.get(key) || "";
    return {
      action,
      type: read("type"),
      id: read("id"),
      postId: read("postId"),
      commentId: read("commentId"),
      subTab: read("subTab"),
      openComments: read("openComments") === "1",
      open: read("open"),
      game: read("game"),
    };
  } catch (_) {
    return null;
  }
}

function urlBase64ToUint8Array(base64String) {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const rawData = atob(base64);
  return Uint8Array.from([...rawData].map(c => c.charCodeAt(0)));
}

function uint8ArrayEquals(a, b) {
  if (!a || !b || a.byteLength !== b.byteLength) return false;
  const aa = new Uint8Array(a);
  const bb = new Uint8Array(b);
  return aa.every((v, i) => v === bb[i]);
}

function getPushSupportMessage() {
  if (typeof window === "undefined") return "push unavailable";
  if (!('Notification' in window)) return "notifications are not supported here";
  if (!('serviceWorker' in navigator)) return "service worker is not supported here";
  if (!('PushManager' in window)) return "web push is not supported here";
  if (window.location.protocol !== "https:" && window.location.hostname !== "localhost") return "notifications need HTTPS";
  return "";
}

function getOrCreatePushDeviceId() {
  try {
    const key = "bb_push_device_id";
    let id = localStorage.getItem(key);
    if (!id) {
      id = `${Date.now()}_${Math.random().toString(36).slice(2)}`;
      localStorage.setItem(key, id);
    }
    return id;
  } catch (_) {
    return `${Date.now()}_${Math.random().toString(36).slice(2)}`;
  }
}

async function ensureServiceWorkerRegistered() {
  if (!('serviceWorker' in navigator)) return null;
  const reg = await navigator.serviceWorker.register('/service-worker.js', { scope: '/' });
  return await navigator.serviceWorker.ready.then(() => reg);
}

async function registerPush(playerId, playerName) {
  const unsupported = getPushSupportMessage();
  if (unsupported) throw new Error(unsupported);
  const reg = await ensureServiceWorkerRegistered();
  if (!reg) throw new Error("service worker did not register");

  const permission = await Notification.requestPermission();
  if (permission !== 'granted') throw new Error("notification permission was not granted");

  const appKey = urlBase64ToUint8Array(VAPID_PUBLIC_KEY);
  let sub = await reg.pushManager.getSubscription();
  if (sub?.options?.applicationServerKey && !uint8ArrayEquals(sub.options.applicationServerKey, appKey)) {
    try { await sub.unsubscribe(); } catch (_) {}
    sub = null;
  }
  if (!sub) {
    sub = await reg.pushManager.subscribe({
      userVisibleOnly: true,
      applicationServerKey: appKey,
    });
  }

  const json = sub.toJSON ? sub.toJSON() : sub;
  const record = {
    ...json,
    endpoint: json.endpoint,
    playerId,
    playerName,
    deviceId: getOrCreatePushDeviceId(),
    updatedAt: new Date().toISOString(),
  };
  const all = await storeGet(PUSH_SUBSCRIPTIONS_KEY) || {};
  const next = {
    ...all,
    // Keep one active phone/browser subscription per player so old Home Screen installs
    // do not keep receiving the same alert and causing duplicate notifications.
    [playerId]: [record],
  };
  await storeSet(PUSH_SUBSCRIPTIONS_KEY, next);
  return record;
}

async function sendPush(subscription, title, body, data = {}) {
  if (!subscription?.endpoint) return false;
  try {
    const res = await fetch('/api/send-push', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ subscription, title, body, data }),
    });
    return res.ok;
  } catch (e) {
    console.error('Push send failed', e);
    return false;
  }
}

async function sendPushToPlayers(targetPlayerIds, title, body, data = {}) {
  const ids = [...new Set((targetPlayerIds || []).filter(Boolean))];
  if (!ids.length) return;
  const all = await storeGet(PUSH_SUBSCRIPTIONS_KEY) || {};
  const jobs = [];
  const seenEndpoints = new Set();

  ids.forEach(pid => {
    const rawSubs = Array.isArray(all[pid]) ? all[pid] : all[pid] ? [all[pid]] : [];
    const subs = rawSubs
      .map(sub => sub?.subscription || sub)
      .filter(sub => sub?.endpoint)
      .sort((a, b) => new Date(b.updatedAt || b.createdAt || 0) - new Date(a.updatedAt || a.createdAt || 0));

    // Use only the newest subscription for that player. Old iPhone Home Screen installs
    // can stay registered with Apple and cause duplicate banners if we send to all of them.
    const sub = subs[0];
    if (!sub?.endpoint || seenEndpoints.has(sub.endpoint)) return;
    seenEndpoints.add(sub.endpoint);
    jobs.push(sendPush(sub, title, body, { ...data, playerId: pid }));
  });

  await Promise.allSettled(jobs);
}

function playerNameById(pid) {
  return PLAYERS.find(p => p.id === pid)?.name || "someone";
}

function titleForPush(icon = "🔔") {
  return `${icon} Burton Battlers`;
}

function pingToPush(ping) {
  const fromName = playerNameById(ping.from);
  if (ping.type === "flower") return { icon:"🌸", body:`${fromName} sent you ${ping.emoji || "🌸"} (+${ping.xp || 0} pts)` };
  if (ping.type === "session") return { icon:"⏱️", body:`${fromName} started a ${ping.mode || "3v3"} session ${ping.minutesUntil ? `in ${ping.minutesUntil} min` : "soon"}` };
  if (ping.type === "coinflip") return { icon:"🪙", body:`${fromName} challenged you to a coin flip` };
  if (ping.type === "chaos") return { icon:"🌀", body:`${fromName} launched ${ping.mode || "chaos"}${ping.text ? ` — ${String(ping.text).slice(0, 90)}` : ""}` };
  if (ping.type === "court") return { icon:"⚖️", body:`${fromName} opened a court case${ping.text ? ` — ${String(ping.text).slice(0, 90)}` : ""}` };
  if (ping.type === "job_shift") return { icon:"⏰", body:String(ping.text || "your scheduled shift starts soon").slice(0, 140) };
  return { icon:"🎮", body:`${fromName} wants to run 2s` };
}

function activityToPush(entry) {
  const icon =
    entry?.type === "like" ? "❤️" :
    entry?.type === "comment" ? "💬" :
    entry?.type === "comment_heart" ? "🩷" :
    entry?.type === "post_react" ? "✨" :
    entry?.type === "post" ? "📸" :
    entry?.type === "prop" ? "🎯" :
    "🔔";
  const fromName = entry?.fromName || "someone";
  const actionText = entry?.text || "sent you a notification";
  if (entry?.type === "prop") {
    const message = entry?.message ? ` — ${String(entry.message).slice(0, 120)}` : "";
    return { icon, body: `${fromName} ${actionText}${message}` };
  }
  const message = entry?.message ? ` — "${String(entry.message).slice(0, 90)}"` : "";
  return { icon, body: `${fromName} ${actionText}${message}` };
}

async function sendPushToPlayersOnce(dedupeId, targetPlayerIds, title, body, data = {}) {
  const id = String(dedupeId || `${title}:${body}:${Date.now()}`);
  try {
    const key = "push_sent_log";
    const now = Date.now();
    const log = await storeGet(key).catch(() => ({})) || {};
    if (log[id] && now - Number(log[id]) < 24 * 60 * 60 * 1000) return;
    const entries = Object.entries(log)
      .filter(([_, ts]) => now - Number(ts) < 24 * 60 * 60 * 1000)
      .slice(-250);
    await storeSet(key, { ...Object.fromEntries(entries), [id]: now });
  } catch (_) {}
  return sendPushToPlayers(targetPlayerIds, title, body, data);
}

async function notifyPingPush(ping) {
  if (!ping?.to || ping.to === ping.from) return;
  const msg = pingToPush(ping);
  return sendPushToPlayersOnce(
    `ping:${ping.id || ping.ts || JSON.stringify(ping)}`,
    [ping.to],
    titleForPush(msg.icon),
    msg.body,
    { url:makeNotificationUrl("ping", { type:ping.type || "ping", id:ping.id }), type:ping.type || "ping", id:ping.id }
  );
}

async function notifyActivityPush(entry) {
  if (!entry?.to) return;
  const msg = activityToPush(entry);
  return sendPushToPlayersOnce(
    `activity:${entry.id || entry.ts || JSON.stringify(entry)}`,
    [entry.to],
    titleForPush(msg.icon),
    msg.body,
    { url:makeNotificationUrl((entry.postId || entry.type === "comment" || entry.type === "comment_heart" || entry.type === "like" || entry.type === "post_react") ? "post" : "activity", { type:entry.type || "activity", id:entry.id, postId:entry.postId, commentId:entry.commentId, openComments:(entry.type === "comment" || entry.type === "comment_heart") ? 1 : "" }), type:entry.type || "activity", id:entry.id, postId:entry.postId, commentId:entry.commentId }
  );
}

async function notifyAdminGrantPush(playerId, body, data = {}) {
  if (!playerId || !body) return;
  return sendPushToPlayersOnce(
    `admin_grant:${playerId}:${body}:${Date.now()}`,
    [playerId],
    "🛡️ Admin update",
    body,
    { url:makeNotificationUrl("garage", { type:data.type || "admin_grant" }), type:data.type || "admin_grant" }
  );
}

async function notifyNewPostPush(post) {
  if (!post?.id || !post?.playerId) return;
  const poster = playerNameById(post.playerId);
  const caption = post.caption ? ` — "${String(post.caption).slice(0, 90)}"` : "";
  const targets = PLAYERS.map(p => p.id).filter(pid => pid !== post.playerId);
  return sendPushToPlayersOnce(
    `post:${post.id}`,
    targets,
    "📸 New squad post",
    `${poster} posted something${caption}`,
    { url:makeNotificationUrl("post", { postId:post.id }), type:"post", id:post.id, postId:post.id }
  );
}

async function notifyVoiceJoinPush(playerId) {
  if (!playerId) return;
  const now = Date.now();
  try {
    const key = "voice_join_push_cooldowns";
    const cooldowns = await storeGet(key).catch(() => ({})) || {};
    const last = Number(cooldowns[playerId] || 0);
    if (now - last < 5 * 60 * 1000) return;
    await storeSet(key, { ...cooldowns, [playerId]: now });
  } catch (_) {}
  const targets = PLAYERS.map(p => p.id).filter(pid => pid !== playerId);
  return sendPushToPlayersOnce(
    `voice:${playerId}:${Math.floor(now / (5 * 60 * 1000))}`,
    targets,
    "🎙️ Voice room",
    `${playerNameById(playerId)} joined voice room`,
    { url:makeNotificationUrl("voice", { id:`voice_${playerId}_${now}` }), type:"voice_join", id:`voice_${playerId}_${now}` }
  );
}

async function dispatchPushForStoreChange(key, before, after) {
  if (key === ADMIN_SHOP_ITEMS_KEY || key === "admin_shop_items") {
    return sendPushToPlayersOnce(`admin_shop:${Date.now()}`, [ADMIN_ID], "🛍️ Shop admin saved", "daily shop layout updated", { url:makeNotificationUrl("admin", { type:"shop" }), type:"admin_shop" });
  }
  const listBefore = Array.isArray(before) ? before : [];
  const listAfter = Array.isArray(after) ? after : [];
  const oldIds = new Set(listBefore.map(x => x?.id || x?.ts || JSON.stringify(x)));
  const newItems = listAfter.filter(x => x && !oldIds.has(x.id || x.ts || JSON.stringify(x)));

  if (key === "pings") {
    await Promise.allSettled(newItems.map(p => notifyPingPush(p)));
  }

  if (key === "activity_feed") {
    await Promise.allSettled(newItems.map(e => notifyActivityPush(e)));
  }

  if (key === "posts") {
    await Promise.allSettled(newItems.map(p => notifyNewPostPush(p)));
  }

  if (key === "chat") {
    await Promise.allSettled(newItems.map(m => {
      const sender = playerNameById(m.playerId);
      const targets = PLAYERS.map(p => p.id).filter(pid => pid !== m.playerId);
      const bodyText = String(m.text || "").trim() || (String(m.mediaType || "").startsWith("video") ? "sent a video" : m.mediaUrl ? "sent an image" : "sent a message");
      return sendPushToPlayersOnce(
        `chat:${m.id || m.ts || JSON.stringify(m)}`,
        targets,
        "💬 Team chat",
        `${sender}: ${bodyText.slice(0, 120)}`,
        { url:makeNotificationUrl("chat", { id:m.id }), type:"chat", id:m.id }
      );
    }));
  }

  if (key === "stocks" && after && typeof after === "object" && !Array.isArray(after)) {
    const beforeObj = before && typeof before === "object" && !Array.isArray(before) ? before : {};
    const jobs = Object.entries(after).map(([holdingKey, nextVal]) => {
      const m = String(holdingKey).match(/^(p\d+)_(p\d+)$/);
      if (!m) return null;
      const [, buyerId, targetId] = m;
      if (!buyerId || !targetId || buyerId === targetId) return null;
      const prevVal = beforeObj[holdingKey];
      const prevShares = typeof prevVal === "number" ? prevVal : Number(prevVal?.shares || 0);
      const nextShares = typeof nextVal === "number" ? nextVal : Number(nextVal?.shares || 0);
      if (!Number.isFinite(nextShares) || nextShares <= prevShares) return null;
      const bought = Math.max(0, nextShares - (Number.isFinite(prevShares) ? prevShares : 0));
      return sendPushToPlayersOnce(
        `stock_buy:${holdingKey}:${nextShares.toFixed(4)}`,
        [targetId],
        "📈 Someone bought your stock",
        `${playerNameById(buyerId)} bought ${bought.toFixed(2)} share${bought === 1 ? "" : "s"} of you`,
        { url:makeNotificationUrl("stocks", { type:"stock_buy", buyer:buyerId, id:targetId }), type:"stock_buy", buyer:buyerId, id:targetId }
      );
    }).filter(Boolean);
    await Promise.allSettled(jobs);
  }

  if (key === "completions" && after && typeof after === "object") {
    const beforeObj = before && typeof before === "object" ? before : {};
    const jobs = Object.entries(after).map(([completionKey, value]) => {
      const prev = beforeObj[completionKey];
      if (!value || prev?.status === value.status) return null;
      const target = completionKey.split("__")[1];
      if (!target) return null;
      if (value.status === "approved") return sendPushToPlayersOnce(`training:${completionKey}:approved`, [target], "✅ Training approved", "training approved — +15 pts", { url:makeNotificationUrl("training", { id:completionKey }), type:"training", id:completionKey });
      if (value.status === "rejected") return sendPushToPlayersOnce(`training:${completionKey}:rejected`, [target], "❌ Training needs redo", value.note ? `needs redo: ${value.note}` : "your training needs another look", { url:makeNotificationUrl("training", { id:completionKey }), type:"training", id:completionKey });
      return null;
    }).filter(Boolean);
    await Promise.allSettled(jobs);
  }

  if (key === "active_race") {
    const oldRaceId = before?.objectiveId;
    const newRaceId = after?.objectiveId;
    if (newRaceId && newRaceId !== oldRaceId) {
      const obj = typeof RACE_OBJECTIVES !== "undefined" ? RACE_OBJECTIVES.find(o => o.id === newRaceId) : null;
      const targets = PLAYERS.map(p => p.id).filter(pid => pid !== after.startedBy);
      await sendPushToPlayersOnce(`race:${newRaceId}:${after?.startedAt || Date.now()}`, targets, `${obj?.emoji || "🏁"} Race started`, `${playerNameById(after.startedBy)} started a race — join now${obj?.label ? ` · ${obj.label}` : ""}${after?.entryFee ? ` · ${after.entryFee} pts jar` : ""}`, { url:makeNotificationUrl("boost", { type:"race", id:newRaceId, open:"race" }), type:"race", id:newRaceId, open:"race" });
    }
  }

  if (key === "credit_requests") {
    await Promise.allSettled(newItems.map(req => {
      const target = req.status === "sent" || req.status === "approved" || req.status === "denied" ? req.playerId : ADMIN_ID;
      const body = req.status === "sent" || req.status === "approved"
        ? `parse credits updated: ${req.amount || ""}`
        : req.status === "denied"
          ? "your parse credit request was denied"
          : `${req.playerName || "someone"} requested parse credits`;
      return sendPushToPlayersOnce(`credits:${req.id || req.ts || JSON.stringify(req)}:${req.status || "new"}`, [target], "🔔 Burton Battlers", body, { url:makeNotificationUrl("admin", { type:"credits", id:req.id }), type:"credits", id:req.id });
    }));
  }
}

const BB_STORE_WRITE_CACHE = new Map();
const BB_PUSH_DIFF_KEYS = new Set([
  "pings", "activity_feed", "posts", "chat", "stocks", "completions",
  "active_race", "credit_requests", ADMIN_SHOP_ITEMS_KEY, "admin_shop_items"
]);
function bbStableStorageString(value) {
  try { return JSON.stringify(value); } catch (_) { return String(Date.now()); }
}
async function storeSetWithPush(key, value) {
  const snapshot = bbStableStorageString(value);
  if (BB_STORE_WRITE_CACHE.get(key) === snapshot) return;
  const needsPushDiff = BB_PUSH_DIFF_KEYS.has(key);
  let before = null;

  // In CPU/Supabase light mode, do not pre-read for ordinary writes. That old read-before-write
  // doubled Supabase work on points/bets/pass saves. Keep the pre-read only for keys that send push alerts.
  if (needsPushDiff) {
    before = await storeGet(key).catch(() => null);
    const beforeSnapshot = bbStableStorageString(before);
    if (beforeSnapshot === snapshot) {
      BB_STORE_WRITE_CACHE.set(key, snapshot);
      return;
    }
  }

  BB_STORE_WRITE_CACHE.set(key, snapshot);
  await storeSet(key, value);
  if (needsPushDiff) dispatchPushForStoreChange(key, before, value).catch(e => console.error("push mirror failed", e));
}

async function showLocalNotification(title, body, data = {}) {
  if (typeof window === "undefined" || !("Notification" in window) || Notification.permission !== "granted") return;
  // Phone-style notifications should only fire when the app is not visible.
  // When the app is open, keep the UI clean and let the notification hub hold it instead.
  if (typeof document !== "undefined" && !document.hidden) return;
  try {
    const reg = await ensureServiceWorkerRegistered();
    await reg?.showNotification(title, { body, icon:"/icon-192.png", badge:"/icon-192.png", data:{ url:"/", ...data } });
  } catch (e) {
    console.error("local notification failed", e);
  }
}
// ===================== Boost Tab =====================
const WHEEL_SEGMENTS = [
  { label: "GOAL 🎯", mult: 2.0, color: "#B8FF4D", prob: 0.22 },
  { label: "SAVE 🧤", mult: 1.5, color: "#7EB8FF", prob: 0.20 },
  { label: "ASSIST 🍀", mult: 1.75, color: "#A78BFA", prob: 0.18 },
  { label: "EPIC SAVE ⭐", mult: 3.0, color: "#FFD166", prob: 0.08 },
  { label: "HAT TRICK 🪖", mult: 4.0, color: "#FF5C8A", prob: 0.05 },
  { label: "DEMO 💥", mult: 0.0, color: "#FF8C42", prob: 0.12 },
  { label: "OWN GOAL 😬", mult: 0.5, color: "#8B92A8", prob: 0.10 },
  { label: "FORFEIT ❌", mult: 0.0, color: "#4A5066", prob: 0.05 },
];

function pickSegment() {
  const r = Math.random();
  let cum = 0;
  for (const seg of WHEEL_SEGMENTS) {
    cum += seg.prob;
    if (r <= cum) return seg;
  }
  return WHEEL_SEGMENTS[0];
}

function calcOdds(pct) {
  if (pct >= 0.5) {
    return { favorite: true, american: `-${Math.round((pct / (1 - pct)) * 100)}`, decimal: (1 / pct).toFixed(2) };
  } else {
    return { favorite: false, american: `+${Math.round(((1 - pct) / pct) * 100)}`, decimal: (1 / pct).toFixed(2) };
  }
}

function calcPayout(wager, decimalOdds) {
  const dec = parseFloat(decimalOdds);
  if (!Number.isFinite(dec) || dec <= 0) return Math.round(Number(wager) || 0);
  return Math.round((Number(wager) || 0) * dec);
}

function clampWager(value, fallback = 1) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(1, Math.min(200, Math.floor(n)));
}

function nextTenAmIso(from = new Date()) {
  const d = new Date(from);
  d.setDate(d.getDate() + 1);
  d.setHours(10, 0, 0, 0);
  return d.toISOString();
}

function nextNoonEasternIso(from = new Date()) {
  try {
    const now = from instanceof Date ? from : new Date(from);
    const parts = new Intl.DateTimeFormat("en-US", { timeZone:"America/New_York", year:"numeric", month:"2-digit", day:"2-digit", hour:"2-digit", minute:"2-digit", hour12:false }).formatToParts(now);
    const get = (t) => parts.find(p => p.type === t)?.value;
    const y = Number(get("year"));
    const m = Number(get("month"));
    const d = Number(get("day"));
    const h = Number(get("hour"));
    const min = Number(get("minute"));
    const targetEtDate = new Date(Date.UTC(y, m - 1, d + ((h > 12 || (h === 12 && min >= 0)) ? 1 : 0), 17, 0, 0)); // noon ET is 17:00 UTC during EDT
    return targetEtDate.toISOString();
  } catch (_) {
    const d = new Date(from);
    d.setDate(d.getDate() + 1);
    d.setHours(12, 0, 0, 0);
    return d.toISOString();
  }
}
function compactTimeLeft(ms) {
  const total = Math.max(0, Math.floor(Number(ms) || 0));
  const hrs = Math.floor(total / 3600000);
  const mins = Math.floor((total % 3600000) / 60000);
  if (hrs >= 24) return `${Math.floor(hrs / 24)}d ${hrs % 24}h`;
  if (hrs > 0) return `${hrs}h ${mins}m`;
  return `${mins}m`;
}
function nextWeeklyChallengeResetIso(from = new Date()) {
  const d = new Date(from);
  d.setHours(0,0,0,0);
  const daysUntilSunday = (7 - d.getDay()) % 7 || 7;
  d.setDate(d.getDate() + daysUntilSunday);
  return d.toISOString();
}
function getBoostUseResetAt(points, playerId, type) {
  const raw = points?.[`${playerId}_${type}ResetAt`];
  const t = raw ? safeDateObj(raw, null).getTime() : NaN;
  return Number.isFinite(t) ? t : null;
}
function withBoostResetStamp(nextPoints, playerId, type, leftAfterUse) {
  const key = `${playerId}_${type}ResetAt`;
  const cur = nextPoints?.[key];
  if (leftAfterUse <= 0 && !cur) return { ...nextPoints, [key]: new Date(Date.now() + DAY_MS).toISOString() };
  if (leftAfterUse > 0 && cur) {
    const clean = { ...nextPoints };
    delete clean[key];
    return clean;
  }
  return nextPoints;
}
function isLightBackgroundValue(value) {
  return ["whiteout", "spring", "snow", "ice", "holo", "gold"].includes(String(value || "").toLowerCase());
}
function getReadableTextForBackground(points, playerId, theme = {}, userColor = "#B8FF4D") {
  const owned = Array.isArray(points?.[playerId + "_owned"]) ? points[playerId + "_owned"] : [];
  const eq = points?.[playerId + "_equipped"] || {};
  const bgId = owned.find(id => eq[id] && getAllShopItems().find(i => i.id === id && i.type === "background"));
  const bgItem = bgId ? getAllShopItems().find(i => i.id === bgId) : null;
  if (bgItem && isLightBackgroundValue(bgItem.value)) {
    return { main:"#05070E", muted:"#202638", accent:"#11131F" };
  }
  if (bgItem) return { main:"#F7F8FF", muted:"#C9D0E4", accent:userColor || "#B8FF4D" };
  return {};
}

function getBetSettleAt(bet) {
  return bet?.settleAt || nextTenAmIso(new Date(bet?.placedAt || bet?.ts || Date.now()));
}

function getBetResultFromGame(bet, game) {
  if (!game) return { status:"void", note:"no logged game before settlement" };
  if (bet?.field === "__match_win" || bet?.type === "match_winner") {
    const wonGame = gameIsWin(game);
    const pickedWin = String(bet.side || "").toLowerCase() === "over" || String(bet.pick || "").toLowerCase() === "win";
    const hit = pickedWin ? wonGame : !wonGame;
    return { status:hit ? "won" : "lost", note:`${game.playerName || bet.playerName || "player"} ${wonGame ? "won" : "lost"} ${getBetMode(bet)}`, actual:wonGame ? 1 : 0, targetGameId:game.id };
  }
  const value = Number(game?.[bet.field]);
  const line = Number(bet.line);
  if (!Number.isFinite(value) || !Number.isFinite(line)) return { status:"void", note:"missing stat data" };
  const won = bet.side === "over" ? value > line : value < line;
  return {
    status: won ? "won" : "lost",
    note: `${game.playerName || bet.playerName || "player"} had ${value} ${bet.field}`,
    actual: value,
    targetGameId: game.id,
  };
}

function getBetMode(bet) {
  const raw = String(bet?.targetMode || bet?.mode || "3v3").replace(/^next_/, "");
  const mode = normalizeGameMode(raw);
  return ["1v1", "2v2", "3v3"].includes(mode) ? mode : "3v3";
}

function formatBetModeLabel(bet = {}) {
  if (bet?.isParlay && Array.isArray(bet.legs)) {
    const modes = Array.from(new Set(bet.legs.map(getBetMode).filter(Boolean)));
    return modes.length ? modes.join("/") : "3v3";
  }
  return getBetMode(bet);
}

function betMatchesModeFilter(bet = {}, mode = "all") {
  if (!mode || mode === "all") return true;
  return formatBetModeLabel(bet).split("/").includes(mode);
}

function getBetAwardAmount(bet = {}, status = "", result = {}) {
  const wager = Math.max(0, Math.round(Number(bet?.wager || 0)));
  if (status === "void") return wager;
  if (status !== "won") return 0;
  const resultAward = Number(result?.splitAward);
  if (bet?.isParlay && bet?.splitPayoutEnabled && Number.isFinite(resultAward)) {
    return capParlayPayout(resultAward);
  }
  const payout = Math.max(0, Math.round(Number(bet?.payout || 0)));
  // The saved payout is the final return for the bet/parlay. Never multiply it again during settlement.
  return bet?.isParlay ? capParlayPayout(payout) : payout;
}

function formatSingleBetTitle(bet = {}) {
  if (bet?.type === "match_winner" || bet?.field === "__match_win") {
    const subject = bet.playerName || playerNameById(bet.playerId) || "player";
    const pick = String(bet.side || "").toLowerCase() === "over" ? "to win" : "to lose";
    return `${subject} ${getBetMode(bet)} ${pick}`;
  }
  if (bet?.type === "rivalry") {
    const pick = bet.pickPlayerName || playerNameById(bet.pickPlayerId) || "player";
    const opp = bet.opponentPlayerName || playerNameById(bet.opponentPlayerId) || "opponent";
    const field = bet.fieldLabel || bet.field || "stat";
    return `${pick} beats ${opp} in ${field}`;
  }
  const field = bet.fieldLabel || bet.marketLabel || bet.field || bet.market || "prop";
  const rawQuestion = String(bet.question || "").trim();
  if (rawQuestion && !/^bet$/i.test(rawQuestion)) return rawQuestion;
  const subject = bet.combined && bet.duoLabel ? bet.duoLabel : (bet.playerName || bet.team || bet.subject || "prop");
  const side = bet.side ? String(bet.side).toLowerCase().replace(/^./, c => c.toUpperCase()) : "";
  const line = bet.line !== undefined && bet.line !== null && bet.line !== "" ? bet.line : "";
  return `${subject} ${side} ${line} ${field}`.replace(/\s+/g, " ").trim() || "prop bet";
}

function formatBetForDisplay(bet = {}) {
  if (bet?.isParlay) {
    const legs = Array.isArray(bet.legs) ? bet.legs : [];
    return {
      title: `${legs.length || 0}-leg${bet.splitPayoutEnabled ? " split" : ""} parlay`,
      sub: bet.splitPayoutEnabled ? "partial legs pay at reduced payout" : "",
      legs: legs.map(leg => formatSingleBetTitle(leg)),
    };
  }
  const title = formatSingleBetTitle(bet);
  return { title, sub: "" };
}

async function notifyPropBetPlacedPush(bet) {
  if (!bet?.id || !bet?.bettorId) return;
  const targetIds = new Set();
  if (bet.isParlay) {
    (Array.isArray(bet.legs) ? bet.legs : []).forEach(leg => {
      if (leg?.combined && Array.isArray(leg.duoIds)) leg.duoIds.forEach(id => targetIds.add(id));
      else if (leg?.playerId) targetIds.add(leg.playerId);
    });
  } else if (bet.type === "rivalry") {
    if (bet.pickPlayerId) targetIds.add(bet.pickPlayerId);
    if (bet.opponentPlayerId) targetIds.add(bet.opponentPlayerId);
  } else if (bet.combined && Array.isArray(bet.duoIds)) {
    bet.duoIds.forEach(id => targetIds.add(id));
  } else if (bet.playerId) {
    targetIds.add(bet.playerId);
  }
  targetIds.delete(bet.bettorId);
  const targets = [...targetIds].filter(Boolean);
  if (!targets.length) return;
  const display = formatBetForDisplay(bet);
  const bettor = playerNameById(bet.bettorId);
  const stake = Number(bet.wager || 0);
  const payout = Number(bet.payout || 0);
  const body = `${bettor} placed ${display.title}${display.sub ? ` — ${display.sub}` : ""}${stake ? ` · ${stake} pts` : ""}${payout ? ` to win ${payout}` : ""}`;
  return sendPushToPlayersOnce(
    `bet-placed:${bet.id}`,
    targets,
    "🎯 New prop on you",
    body,
    { url:makeNotificationUrl("social", { subTab:"bets", id:bet.id }), type:"prop_placed", id:bet.id }
  );
}

function duoMatchesGame(game, duoIds) {
  if (!Array.isArray(duoIds) || duoIds.length < 2) return true;
  const ids = Array.isArray(game?.duoIds) ? game.duoIds : [];
  // Old logs may not have duoIds. Do not block those from resolving.
  if (!ids.length) return true;
  return duoIds.every(id => ids.includes(id));
}

function getBetGameKey(game) {
  if (!game || typeof game !== "object") return "";
  return String(
    game.id ||
    game.parseMatchId ||
    game.matchId ||
    `${game.playerId || "player"}_${normalizeGameMode(game.mode)}_${game.sessionCode || game.roomId || "session"}_${game.ts || game.date || "time"}`
  );
}

function getBetSeenGameKeysForPlacement(stats = [], bet = null) {
  const mode = bet ? getBetMode(bet) : null;
  const playerId = bet?.playerId || null;
  const duoIds = bet?.duoIds || null;
  return sanitizeStatsForRender(stats)
    .filter(g => {
      if (!g) return false;
      if (mode && normalizeGameMode(g.mode) !== mode) return false;
      if (playerId && !bet?.combined && g.playerId !== playerId) return false;
      if (duoIds && !duoMatchesGame(g, duoIds)) return false;
      return true;
    })
    .map(getBetGameKey)
    .filter(Boolean);
}

const BET_PLACEMENT_GRACE_MS = 2000;

function betTimeValue(...values) {
  for (const value of values) {
    if (value === null || value === undefined || value === "") continue;
    const t = value instanceof Date ? value.getTime() : new Date(value).getTime();
    if (Number.isFinite(t) && t > 0) return t;
  }
  return 0;
}

function betCandidateSortTime(game) {
  return betTimeValue(
    game?.syncedAt,
    game?.importedAt,
    game?.createdAt,
    game?.matchStartAt,
    game?.ts,
    game?.date
  );
}

function betGameIsAfterPlacement(game, placedAtMs) {
  if (!Number.isFinite(placedAtMs) || placedAtMs <= 0) return true;

  const newestGameTime = Math.max(
    betTimeValue(game?.syncedAt),
    betTimeValue(game?.importedAt),
    betTimeValue(game?.createdAt),
    betTimeValue(game?.matchStartAt),
    betTimeValue(game?.ts),
    betTimeValue(game?.date)
  );

  return newestGameTime >= placedAtMs - BET_PLACEMENT_GRACE_MS;
}

function findBetTargetGame(bet, stats = [], options = {}) {
  const placedAt = safeDateObj(bet?.placedAt || bet?.ts || 0, 0).getTime();
  const mode = getBetMode(bet);
  const enforcePreMatchLock = options.enforcePreMatchLock !== false;
  const seenKeys = new Set(Array.isArray(bet?.statKeysAtPlacement) ? bet.statKeysAtPlacement.map(String) : []);

  const allGames = sanitizeStatsForRender(stats)
    .filter(g => {
      if (!g || normalizeGameMode(g.mode) !== mode) return false;

      const key = getBetGameKey(g);
      if (seenKeys.size && (!key || seenKeys.has(String(key)))) return false;

      // Critical: bets are for the next synced/logged match after placement.
      // An old stat row with a new/unseen key cannot settle a new bet unless
      // it was actually synced/imported/created after the bet was placed.
      if (!betGameIsAfterPlacement(g, placedAt)) return false;

      if (enforcePreMatchLock && !propBetWasPlacedBeforeGameStarted(bet, g)) return false;

      return true;
    })
    .sort((a, b) => betCandidateSortTime(a) - betCandidateSortTime(b));

  if (bet?.combined && Array.isArray(bet?.duoIds) && bet.duoIds.length >= 2) {
    const wanted = new Set(bet.duoIds);
    const groups = {};

    allGames
      .filter(g => wanted.has(g.playerId) && duoMatchesGame(g, bet.duoIds))
      .forEach(g => {
        const ts = safeDateObj(g.ts || g.matchStartAt || g.syncedAt || g.importedAt || g.createdAt);
        const key = g.sessionCode || g.roomId || g.matchId || g.parseMatchId || `${dateKey(ts)}_${mode}_${Math.floor(ts.getTime() / 60000)}`;

        if (!groups[key]) {
          groups[key] = {
            key,
            ts: g.ts || g.matchStartAt || g.syncedAt || g.importedAt || g.createdAt,
            syncedAt: g.syncedAt || g.importedAt || g.createdAt || g.ts || g.matchStartAt,
            games: [],
          };
        }

        groups[key].games.push(g);

        if (betCandidateSortTime(g) > safeDateObj(groups[key].syncedAt || groups[key].ts).getTime()) {
          groups[key].syncedAt = g.syncedAt || g.importedAt || g.createdAt || g.ts || g.matchStartAt;
        }

        if (safeDateObj(g.ts || g.matchStartAt || 0).getTime() > safeDateObj(groups[key].ts || 0).getTime()) {
          groups[key].ts = g.ts || g.matchStartAt;
        }
      });

    const group = Object.values(groups)
      .filter(grp => {
        const logged = new Set(grp.games.map(g => g.playerId).filter(Boolean));
        return bet.duoIds.every(id => logged.has(id)) || grp.games.length >= 2;
      })
      .sort((a, b) => safeDateObj(a.syncedAt || a.ts).getTime() - safeDateObj(b.syncedAt || b.ts).getTime())[0];

    if (!group) return null;

    const field = bet.field || "goals";
    const value = group.games.reduce((sum, g) => sum + (Number(g[field]) || 0), 0);

    return {
      ...(group.games[0] || {}),
      id: `duo_prop_${group.key}`,
      playerName: bet.playerName || bet.duoLabel || "duo",
      ts: group.ts,
      syncedAt: group.syncedAt || group.ts,
      mode,
      [field]: value,
    };
  }

  return allGames
    .filter(g =>
      g.playerId === bet.playerId &&
      duoMatchesGame(g, bet.duoIds)
    )[0] || null;
}

function findRivalryTargetGames(bet, stats = [], options = {}) {
  if (!bet || bet.type !== "rivalry") return null;
  const pickId = bet.pickPlayerId || bet.playerId;
  const opponentId = bet.opponentPlayerId;
  if (!pickId || !opponentId || pickId === opponentId) return null;
  const base = {
    ...bet,
    combined:false,
    duoIds:null,
    line:0,
    side:"over",
    targetMode: bet.targetMode || bet.mode || "3v3",
  };
  const pickGame = findBetTargetGame({ ...base, playerId: pickId }, stats, options);
  const opponentGame = findBetTargetGame({ ...base, playerId: opponentId }, stats, options);
  if (!pickGame || !opponentGame) return null;
  return { pickGame, opponentGame };
}

function getRivalryBetResult(bet, stats = []) {
  const games = findRivalryTargetGames(bet, stats);
  if (!games) return { status:"pending", note:"waiting for both rivalry stats" };
  const field = bet.field || "goals";
  if (field === "match_winner") {
    const won = gameIsWin(games.pickGame);
    return { status:won ? "won" : "lost", note:`${bet.pickPlayerName || playerNameById(bet.pickPlayerId)} ${won ? "won" : "lost"} ${bet.targetMode || "game"}`, targetGameId:games.pickGame?.id, opponentTargetGameId:games.opponentGame?.id };
  }
  const pickValue = Number(games.pickGame?.[field]);
  const oppValue = Number(games.opponentGame?.[field]);
  if (!Number.isFinite(pickValue) || !Number.isFinite(oppValue)) return { status:"void", note:"missing rivalry stat data" };
  if (pickValue === oppValue) {
    return {
      status:"void",
      note:`rivalry pushed: both had ${pickValue} ${bet.fieldLabel || field}`,
      actual:pickValue,
      opponentActual:oppValue,
      targetGameId:games.pickGame?.id,
      opponentTargetGameId:games.opponentGame?.id,
    };
  }
  const won = pickValue > oppValue;
  return {
    status:won ? "won" : "lost",
    note:`${bet.pickPlayerName || playerNameById(bet.pickPlayerId)} ${pickValue} vs ${bet.opponentPlayerName || playerNameById(bet.opponentPlayerId)} ${oppValue} ${bet.fieldLabel || field}`,
    actual:pickValue,
    opponentActual:oppValue,
    targetGameId:games.pickGame?.id,
    opponentTargetGameId:games.opponentGame?.id,
  };
}

function findBetLateLockedGame(bet, stats = []) {
  const game = findBetTargetGame(bet, stats, { enforcePreMatchLock: false });
  if (!game) return null;
  return propBetWasPlacedBeforeGameStarted(bet, game) ? null : game;
}

function getMergedParlayLeg(leg, bet) {
  return {
    ...leg,
    placedAt: leg?.placedAt || bet?.placedAt,
    ts: leg?.ts || bet?.ts,
    settleAt: leg?.settleAt || getBetSettleAt(bet),
    statKeysAtPlacement: Array.isArray(leg?.statKeysAtPlacement) ? leg.statKeysAtPlacement : (bet?.statKeysAtPlacement || []),
  };
}

function betHasLateLockedGame(bet, stats = []) {
  if (bet?.isParlay) {
    return (Array.isArray(bet.legs) ? bet.legs : []).some(leg => !!findBetLateLockedGame(getMergedParlayLeg(leg, bet), stats));
  }
  return !!findBetLateLockedGame(bet, stats);
}

function betLateLockedResult(bet, game) {
  const value = Number(game?.[bet?.field]);
  return {
    status:"lost",
    note:"bet placed after the match started",
    actual:Number.isFinite(value) ? value : undefined,
    targetGameId:game?.id,
    lateLocked:true,
  };
}

function getParlayLegResult(leg, bet, stats = []) {
  const merged = getMergedParlayLeg(leg, bet);
  const lateGame = findBetLateLockedGame(merged, stats);
  if (lateGame) return { ...betLateLockedResult(merged, lateGame), leg: merged, resolved:true };
  const game = findBetTargetGame(merged, stats);
  const result = getBetResultFromGame(merged, game);
  return { ...result, leg: merged, resolved: result.status !== "void" };
}

function parlayHasResolvedLegs(bet, stats = []) {
  const legs = Array.isArray(bet?.legs) ? bet.legs : [];
  if (!legs.length) return false;
  return legs.every(leg => getParlayLegResult(leg, bet, stats).resolved);
}

function betHasTargetGame(bet, stats = []) {
  if (bet?.type === "rivalry") return !!findRivalryTargetGames(bet, stats);
  if (bet?.isParlay) return parlayHasResolvedLegs(bet, stats);
  return !!findBetTargetGame(bet, stats);
}

function resolveSingleBet(bet, stats = []) {
  if (bet?.type === "rivalry") return getRivalryBetResult(bet, stats);
  if (bet?.isParlay) {
    const legResults = (bet.legs || []).map(leg => getParlayLegResult(leg, bet, stats));
    if (!legResults.length || legResults.some(r => r.status === "void")) {
      return { status:"pending", note:"waiting for every parlay leg to get a synced stat", legResults };
    }
    if (legResults.some(r => r.lateLocked)) return { status:"lost", note:"one or more legs were placed after match start", lateLocked:true, legResults };
    const wonLegs = legResults.filter(r => r.status === "won").length;
    const totalLegs = legResults.length;
    if (bet?.splitPayoutEnabled) {
      if (wonLegs > 0) {
        const splitAward = calcSplitParlayAwardFromPayout(bet.fullPayoutBeforeSplit || bet.payout, wonLegs, totalLegs);
        return {
          status:"won",
          note: wonLegs === totalLegs ? `split parlay hit all ${totalLegs} legs` : `split parlay paid ${wonLegs}/${totalLegs} legs`,
          legResults,
          splitAward,
          splitWonLegs: wonLegs,
          splitTotalLegs: totalLegs,
        };
      }
      return { status:"lost", note:"split parlay missed every leg", legResults, splitWonLegs:0, splitTotalLegs:totalLegs };
    }
    if (wonLegs === totalLegs) return { status:"won", note:"all parlay legs hit", legResults };
    return { status:"lost", note:"one or more parlay legs missed", legResults };
  }

  if (!bet?.playerId || !bet?.field || !bet?.side) return { status:"void", note:"unsupported bet type" };
  const lateGame = findBetLateLockedGame(bet, stats);
  if (lateGame) return betLateLockedResult(bet, lateGame);
  return getBetResultFromGame(bet, findBetTargetGame(bet, stats));
}

function settledBetPushBody(bet) {
  if (bet?.type === "rivalry") {
    const subject = formatSingleBetTitle(bet);
    if (bet.status === "won") return `${subject} - +${bet.wonAmount ?? bet.payout ?? 0}pts`;
    if (bet.status === "void") return `${subject} - pushed +${bet.wager || 0}pts`;
    return `${subject} - lost`;
  }
  if (bet?.isParlay) {
    const subject = `${bet.legs?.length || 0}-leg parlay`;
    if (bet.status === "won") return `${subject} - +${bet.wonAmount ?? bet.splitAward ?? bet.payout ?? 0}pts`;
    if (bet.status === "void") return `${subject} - voided +${bet.wager || 0}pts`;
    return `${subject} - lost`;
  }
  const side = String(bet.side || "").toLowerCase() === "under" ? "Under" : "Over";
  const subject = `${bet.playerName || "your prop"} ${side} ${bet.line ?? ""} ${bet.fieldLabel || bet.field || ""}`.replace(/\s+/g, " ").trim();
  if (bet.status === "won") return `${subject} - +${bet.wonAmount ?? bet.splitAward ?? bet.payout ?? 0}pts`;
  if (bet.status === "void") return `${subject} - voided +${bet.wager || 0}pts`;
  return `${subject} - lost${bet.lateLocked ? " (late bet)" : ""}`;
}

function betTouchesAnyGameId(bet, gameIds) {
  if (!bet || !gameIds?.size) return false;
  if (bet.targetGameId && gameIds.has(String(bet.targetGameId))) return true;
  return (Array.isArray(bet.legResults) ? bet.legResults : []).some(r => r?.targetGameId && gameIds.has(String(r.targetGameId)));
}
async function regradeLostBetsForGames({ bets, stats, points, setBets, setPoints, games }) {
  const gameIds = new Set((games || []).map(g => String(g?.id || "")).filter(Boolean));
  if (!gameIds.size) return false;
  const list = Array.isArray(bets) ? bets : [];
  const affected = list.filter(b => b?.status === "lost" && betTouchesAnyGameId(b, gameIds));
  if (!affected.length) return false;
  const affectedIds = new Set(affected.map(b => b.id));
  const freshPoints = await storeGet("points").catch(() => points) || points || {};
  const nextPoints = { ...freshPoints };
  const paidBetIds = new Set(Array.isArray(nextPoints.__paidBetIds) ? nextPoints.__paidBetIds.map(String) : []);
  let changed = false;
  const nextBets = list.map(b => {
    if (!affectedIds.has(b.id)) return b;
    const result = resolveSingleBet({ ...b, status:"open" }, stats);
    if (!['won', 'void'].includes(result.status)) return b;
    changed = true;
    const payKey = String(b.id || "");
    const shouldPay = !!payKey && !paidBetIds.has(payKey);
    const award = shouldPay ? getBetAwardAmount(b, result.status, result) : 0;
    if (shouldPay && award > 0) {
      nextPoints[b.bettorId] = (Number(nextPoints[b.bettorId]) || 0) + award;
      paidBetIds.add(payKey);
    }
    return {
      ...b,
      status: result.status,
      regradedAt: new Date().toISOString(),
      settlementNote: `regraded after live stats refreshed — ${result.note}`,
      actual: result.actual,
      opponentActual: result.opponentActual,
      targetGameId: result.targetGameId,
      opponentTargetGameId: result.opponentTargetGameId,
      lateLocked: !!result.lateLocked,
      splitAward: result.splitAward,
      splitWonLegs: result.splitWonLegs,
      splitTotalLegs: result.splitTotalLegs,
      legResults: Array.isArray(result.legResults) ? result.legResults.map(r => ({ status:r.status, note:r.note, actual:r.actual, targetGameId:r.targetGameId, lateLocked:!!r.lateLocked })) : b.legResults,
      wonAmount: award,
    };
  });
  if (!changed) return false;
  nextPoints.__paidBetIds = Array.from(paidBetIds).slice(-600);
  setPoints?.(nextPoints);
  setBets?.(nextBets);
  await storeSet("points", nextPoints);
  await storeSet("bets", nextBets);
  return true;
}

async function settleDueBetsNow({ bets, stats, points, setBets, setPoints }) {
  const list = Array.isArray(bets) ? bets : [];
  const due = list.filter(b => {
    if (b?.status !== "open") return false;
    // Props are for the next logged/synced game, so never auto-void just because the old timer passed.
    // Only settle once an actual matching stat exists, which keeps notifications as WIN/LOSS after sync.
    return betHasTargetGame(b, stats) || betHasLateLockedGame(b, stats);
  });
  if (!due.length) return false;

  const freshPoints = await storeGet("points").catch(() => points) || points || {};
  const nextPoints = { ...freshPoints };
  const paidBetIds = new Set(Array.isArray(nextPoints.__paidBetIds) ? nextPoints.__paidBetIds.map(String) : []);
  const dueIds = new Set(due.map(d => d.id));
  const nextBets = list.map(b => {
    if (!dueIds.has(b.id)) return b;
    const result = resolveSingleBet(b, stats);
    if (!["won", "lost", "void"].includes(result.status)) return b;
    const payKey = String(b.id || "");
    const shouldPay = (result.status === "won" || result.status === "void") && !!payKey && !paidBetIds.has(payKey);
    const award = shouldPay ? getBetAwardAmount(b, result.status, result) : 0;
    if (shouldPay && award > 0) {
      nextPoints[b.bettorId] = (Number(nextPoints[b.bettorId]) || 0) + award;
      paidBetIds.add(payKey);
    }
    return {
      ...b,
      status: result.status,
      settledAt: new Date().toISOString(),
      settlementNote: result.note,
      actual: result.actual,
      opponentActual: result.opponentActual,
      targetGameId: result.targetGameId,
      opponentTargetGameId: result.opponentTargetGameId,
      lateLocked: !!result.lateLocked,
      splitAward: result.splitAward,
      splitWonLegs: result.splitWonLegs,
      splitTotalLegs: result.splitTotalLegs,
      legResults: Array.isArray(result.legResults) ? result.legResults.map(r => ({ status:r.status, note:r.note, actual:r.actual, targetGameId:r.targetGameId, lateLocked:!!r.lateLocked })) : b.legResults,
      wonAmount: getBetAwardAmount(b, result.status, result),
    };
  });

  nextPoints.__paidBetIds = Array.from(paidBetIds).slice(-600);
  setPoints?.(nextPoints);
  setBets?.(nextBets);
  await storeSet("points", nextPoints);
  await storeSet("bets", nextBets);

  const settledNow = nextBets.filter(nb => dueIds.has(nb.id) && nb.status && nb.status !== "open");
  const byBettor = settledNow.reduce((acc, b) => { if (!b?.bettorId) return acc; (acc[b.bettorId] ||= []).push(b); return acc; }, {});
  await Promise.allSettled(Object.entries(byBettor).map(async ([bettorId, settledList]) => {
    if (settledList.length === 1) {
      const settled = settledList[0];
      return sendPushToPlayersOnce(
        `bet-settled:${settled.id}:${settled.status}`,
        [bettorId],
        settled.status === "won" ? "✅ Prop won" : settled.status === "lost" ? "❌ Prop lost" : "↩️ Prop voided",
        settledBetPushBody(settled),
        { url:makeNotificationUrl("social", { subTab:"bets", id:settled.id }), type:"bet_settled", id:settled.id }
      );
    }
    const won = settledList.filter(b => b.status === "won").length;
    const lost = settledList.filter(b => b.status === "lost").length;
    const voided = settledList.filter(b => b.status === "void").length;
    const gained = settledList.reduce((sum,b)=>sum + (b.status === "won" ? Number((b.wonAmount ?? b.splitAward ?? b.payout) || 0) : b.status === "void" ? Number(b.wager||0) : 0), 0);
    return sendPushToPlayersOnce(
      `bet-settled-batch:${bettorId}:${settledList.map(b=>b.id).join("_")}`,
      [bettorId],
      "🎰 Your bets settled",
      `${settledList.length} bets settled · ${won}W ${lost}L${voided ? ` ${voided}V` : ""} · ${gained} pts returned`,
      { url:makeNotificationUrl("social", { subTab:"bets" }), type:"bet_settled_batch" }
    );
  }));

  return true;
}

const DAILY_PROMO_PUSHES = [
  { hour:11, title:"🎡 New spins available", body:"come test your luck in Boost." },
  { hour:15, title:"🎯 New props available", body:"check the board before tonight's games." },
  { hour:18, title:"🛒 Daily shop check", body:"see what's waiting in the item shop." },
  { hour:21, title:"🎮 Squad check-in", body:"hop in and see who's on." },
  { hour:0, title:"🌙 Late night boost", body:"new day, new spins, new props." },
];

async function maybeSendScheduledPromoPush(playerId) {
  if (!playerId) return;
  const now = new Date();
  const activePromo = DAILY_PROMO_PUSHES.find(promo => {
    const slot = new Date(now);
    slot.setHours(promo.hour, 0, 0, 0);
    const age = now.getTime() - slot.getTime();
    return age >= 0 && age <= 20 * 60 * 1000;
  });
  // Fast no-op most of the day: avoid a Supabase read every minute when no promo can fire.
  if (!activePromo) return;
  const today = dateKey(now);
  const logKey = `promo_push_log_${playerId}_${today}`;
  const sent = await storeGet(logKey).catch(() => ({})) || {};
  const id = `${today}_${activePromo.hour}`;
  if (sent[id]) return;
  await storeSet(logKey, { ...sent, [id]: true });
  await sendPushToPlayersOnce(`promo:${playerId}:${id}`, [playerId], activePromo.title, activePromo.body, { url:makeNotificationUrl("boost", { type:"promo", id }), type:"promo", id });
}

function StockTrendLine({ priceHistory, color, width = 260, height = 70 }) {
  if (!priceHistory || priceHistory.length < 2) {
    return (
      <div style={{height, display:"flex", alignItems:"center", justifyContent:"center", color:"#4A5066", fontSize:11}}>
        not enough games yet for a chart
      </div>
    );
  }
  const vals = priceHistory.slice(-20);
  const max = Math.max(...vals);
  const min = Math.min(...vals);
  const range = Math.max(1, max - min);
  const pad = 6;
  const w = width, h = height;

  const pts = vals.map((v, i) => {
    const x = pad + (i / (vals.length - 1)) * (w - pad * 2);
    const y = h - pad - ((v - min) / range) * (h - pad * 2);
    return { x, y };
  });

  const linePoints = pts.map(p => `${p.x},${p.y}`).join(" ");
  const areaPoints = `${pts[0].x},${h} ${linePoints} ${pts[pts.length-1].x},${h}`;

  const up = vals[vals.length - 1] >= vals[0];
  const lineColor = color || (up ? "#7CFFB2" : "#FF5C8A");
  const gradId = `stockgrad-${lineColor.replace("#","")}`;

  return (
    <svg width={w} height={h} style={{display:"block"}}>
      <defs>
        <linearGradient id={gradId} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={lineColor} stopOpacity="0.35"/>
          <stop offset="100%" stopColor={lineColor} stopOpacity="0"/>
        </linearGradient>
      </defs>
      <polygon points={areaPoints} fill={`url(#${gradId})`} />
      <polyline points={linePoints} fill="none" stroke={lineColor} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
      {pts.map((p,i)=>(
        i === pts.length - 1
          ? <circle key={i} cx={p.x} cy={p.y} r="3.5" fill={lineColor} style={{filter:`drop-shadow(0 0 4px ${lineColor}99)`}}/>
          : null
      ))}
    </svg>
  );
}


function StockMarketTab({ stats, currentPlayer, points, setPoints, stocks, setStocks, passXP }) {
  const [selectedId,setSelectedId]=useState(PLAYERS.find(p=>p.id!==currentPlayer)?.id || PLAYERS[0].id);
  const [amount,setAmount]=useState(100);
  const [range,setRange]=useState("7d");
  const myPoints = Number(points?.[currentPlayer] || 0);
  const getPlayerXP = (playerId) => getFreePassXPForPlayer(passXP || {}, playerId) + getPremiumPassXPForPlayer(passXP || {}, playerId, !!points?.[`${playerId}_premium`]);
  const getPrice = (playerId, untilTs = Date.now()) => {
    const pg = (stats||[]).filter(g => g.playerId === playerId && safeDateObj(g.ts||g.date).getTime() <= untilTs);
    const wins = pg.filter(gameIsWin).length;
    const xp = getPlayerXP(playerId);
    return Math.max(10, Math.round(STOCK_BASE_PRICE + wins * 8 + Math.floor(xp/100) * 4));
  };
  const getHistory = (playerId) => {
    const now = Date.now();
    const days = range === "1d" ? 1 : range === "14d" ? 14 : range === "28d" ? 28 : 7;
    const span = days * DAY_MS;
    const start = now - span;
    const games = (stats||[]).filter(g=>g.playerId===playerId && safeDateObj(g.ts||g.date).getTime()>=start).sort((a,b)=>safeDateObj(a.ts||a.date)-safeDateObj(b.ts||b.date));
    const pts = [{ts:new Date(start).toISOString(), price:getPrice(playerId,start)}];
    games.forEach(g=>pts.push({ts:g.ts||g.date, price:getPrice(playerId,safeDateObj(g.ts||g.date).getTime())}));
    pts.push({ts:new Date().toISOString(), price:getPrice(playerId)});
    return pts;
  };
  const holdingFor = (pid) => {
    const raw = stocks?.[`${currentPlayer}_${pid}`];
    if (typeof raw === "number") return { shares:raw, invested:raw * getPrice(pid), avg:raw ? getPrice(pid) : 0 };
    if (raw && typeof raw === "object") return { shares:Number(raw.shares)||0, invested:Number(raw.invested)||0, avg:Number(raw.avg)||((Number(raw.invested)||0)/Math.max(Number(raw.shares)||0,1)) };
    return { shares:0, invested:0, avg:0 };
  };
  const buy = async(pid) => {
    const price = getPrice(pid); const shares = Math.max(0, Number(amount)||0) / price;
    if (!shares || myPoints < amount) return;
    const h=holdingFor(pid); const nextH={ shares:h.shares+shares, invested:h.invested+Number(amount), avg:(h.invested+Number(amount))/(h.shares+shares) };
    const upd={...(stocks||{}), [`${currentPlayer}_${pid}`]:nextH, [`${pid}_prevPrice`]:price};
    const pts={...(points||{}), [currentPlayer]:myPoints-Number(amount)};
    setStocks(upd); setPoints(pts); await storeSetWithPush("stocks",upd); await storeSetWithPush("points",pts);
  };
  const sell = async(pid, fraction=1) => {
    const h=holdingFor(pid); if(!h.shares) return;
    const sellShares=h.shares*fraction; const price=getPrice(pid); const value=Math.round(sellShares*price); const remainingShares=h.shares-sellShares; const remainingInvested=h.invested*(remainingShares/Math.max(h.shares,1));
    const nextH={ shares:remainingShares, invested:remainingInvested, avg:remainingShares?remainingInvested/remainingShares:0 };
    const upd={...(stocks||{}), [`${currentPlayer}_${pid}`]:nextH, [`${pid}_prevPrice`]:price};
    const pts={...(points||{}), [currentPlayer]:myPoints+value};
    setStocks(upd); setPoints(pts); await storeSetWithPush("stocks",upd); await storeSetWithPush("points",pts);
  };
  const selected = PLAYERS.find(p=>p.id===selectedId) || PLAYERS[0];
  const price = getPrice(selected.id); const hist=getHistory(selected.id); const h=holdingFor(selected.id); const value=Math.round(h.shares*price); const pnl=value-h.invested;
  return <div className="bb-tab-content" style={s.tabContent}>
    <div style={{fontSize:10,color:"#FFD166",fontWeight:900,letterSpacing:1,textTransform:"uppercase",marginBottom:4}}>portfolio</div>
    <div style={{fontSize:11,color:"#8B92A8",lineHeight:1.4,marginBottom:12}}>buy into player performance. prices move from wins and pass XP only.</div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:12}}>{PLAYERS.map(p=>{ const hp=holdingFor(p.id); const val=Math.round(hp.shares*getPrice(p.id)); return <button key={p.id} onClick={()=>setSelectedId(p.id)} className="bb-pressable" style={{background:selectedId===p.id?bbAlpha(p.color,.14):"rgba(255,255,255,.04)",border:`1px solid ${selectedId===p.id?bbAlpha(p.color,.32):"rgba(255,255,255,.08)"}`,borderRadius:14,padding:10,textAlign:"left",color:"#E8ECF4"}}><div style={{fontSize:10,color:p.color,fontWeight:900}}>{p.name}</div><div style={{fontSize:16,fontWeight:900,marginTop:3}}>{val}</div><div style={{fontSize:9,color:"#8B92A8"}}>{hp.shares.toFixed(2)} shares</div></button>})}</div>
    <div style={{background:"linear-gradient(135deg,#11131F,#090B14)",border:`1px solid ${bbAlpha(selected.color,.24)}`,borderRadius:20,padding:14,marginBottom:14}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:10,marginBottom:10}}><div><div style={{fontSize:10,color:selected.color,fontWeight:900,letterSpacing:1,textTransform:"uppercase"}}>stock detail</div><div style={{fontSize:20,color:"#E8ECF4",fontWeight:900}}>{selected.name}</div></div><div style={{textAlign:"right"}}><div style={{fontSize:22,color:"#E8ECF4",fontWeight:900}}>{price}</div><div style={{fontSize:10,color:"#8B92A8"}}>pts/share</div></div></div>
      <div style={{display:"flex",gap:7,marginBottom:10}}>{[["1d","1 day"],["7d","7 day"],["14d","14 day"],["28d","28 day"]].map(([r,label])=><button key={r} onClick={()=>setRange(r)} style={{flex:1,background:range===r?selected.color:"rgba(255,255,255,.05)",border:"none",borderRadius:10,padding:8,color:range===r?"#06070D":"#8B92A8",fontSize:10,fontWeight:900}}>{label}</button>)}</div>
      <MiniTrendGraph points={hist} color={selected.color} height={132} showLabels/>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginTop:12}}><div style={{background:"rgba(255,255,255,.04)",borderRadius:12,padding:10}}><div style={{fontSize:9,color:"#4A5066",fontWeight:900}}>SHARES</div><div style={{fontSize:15,color:"#E8ECF4",fontWeight:900}}>{h.shares.toFixed(2)}</div></div><div style={{background:"rgba(255,255,255,.04)",borderRadius:12,padding:10}}><div style={{fontSize:9,color:"#4A5066",fontWeight:900}}>VALUE</div><div style={{fontSize:15,color:"#E8ECF4",fontWeight:900}}>{value}</div></div><div style={{background:"rgba(255,255,255,.04)",borderRadius:12,padding:10}}><div style={{fontSize:9,color:"#4A5066",fontWeight:900}}>P/L</div><div style={{fontSize:15,color:pnl>=0?"#7CFFB2":"#FF5C8A",fontWeight:900}}>{pnl>=0?"+":""}{Math.round(pnl)}</div></div></div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginTop:12}}><input type="number" value={amount} onChange={e=>setAmount(e.target.value)} style={{background:"rgba(255,255,255,.04)",border:"1px solid rgba(255,255,255,.08)",borderRadius:12,padding:"10px",color:"#E8ECF4",fontSize:12}}/><button onClick={()=>buy(selected.id)} className="bb-pressable" style={{background:"#B8FF4D",border:"none",borderRadius:12,color:"#06070D",fontWeight:1000}}>buy</button><button onClick={()=>sell(selected.id,.5)} disabled={!h.shares} className="bb-pressable" style={{background:"rgba(255,209,102,.12)",border:"1px solid rgba(255,209,102,.28)",borderRadius:12,color:h.shares?"#FFD166":"#4A5066",fontWeight:900,padding:10}}>sell half</button><button onClick={()=>sell(selected.id,1)} disabled={!h.shares} className="bb-pressable" style={{background:"rgba(255,92,138,.12)",border:"1px solid rgba(255,92,138,.28)",borderRadius:12,color:h.shares?"#FF5C8A":"#4A5066",fontWeight:900,padding:10}}>sell all</button></div>
    </div>
  </div>;
}

