const pushActivity = async ({ to, type, fromName, text, message = "", gameId = "", postId = "", commentId = "" }) => {
  const existing = await storeGet("activity_feed") || [];

  const entry = {
    id: `${Date.now()}_${Math.random().toString(36).slice(2)}`,
    to,
    type,
    fromName,
    text,
    message,
    gameId,
    postId,
    commentId,
    ts: new Date().toISOString(),
    seen: false
  };

  await storeSet("activity_feed", [entry, ...existing].slice(0, 80));
};             
  const myOpenBets = (bets || []).filter(b => b.bettorId === currentPlayer && b.status === "open");
  const mySettledBets = (bets || []).filter(b => b.bettorId === currentPlayer && b.status !== "open");
  const cancelOpenBet = async (betId) => {
    const updBets = (bets || []).filter(b => b.id !== betId);
    setBets(updBets);
    await storeSet("bets", updBets);
  };
  const cancelAllOpenBets = async () => {
    const updBets = (bets || []).filter(b => !(b.bettorId === currentPlayer && b.status === "open"));
    setBets(updBets);
    await storeSet("bets", updBets);
  };

const spinWheel = async () => {
    if (spinning || wager < 1 || myPoints < wager) return;
    bbHaptic([18, 30, 18]);
    if (spinsLeft <= 0) return;

    const startingPoints = Number(myPoints) || 0;
    setSpinStartPoints(startingPoints);
    setSpinning(true);
    setSpinResult(null);

    const segAngle = 360 / WHEEL_SEGMENTS.length;
    const spins = 5 + Math.floor(Math.random() * 3);
    const targetDeg = spins * 360 + Math.random() * 360;
    const newRotation = rotation + targetDeg;
    setRotation(newRotation);

    setTimeout(async () => {
      const normalizedAngle = (((0 - (newRotation % 360)) + 90 + 360) % 360);
      const segIdx = Math.floor(normalizedAngle / segAngle) % WHEEL_SEGMENTS.length;
      const seg = WHEEL_SEGMENTS[segIdx];
      const payout = Math.round(wager * seg.mult);
      const net = payout - wager;

      const freshPoints = await storeGet("points") || {};
      const currentBalance = Number(freshPoints[currentPlayer] ?? startingPoints) || 0;
      const newPts = Math.max(0, currentBalance - wager + payout);
      let updatedPoints = {
        ...freshPoints,
        [currentPlayer]: newPts,
        [spinCountKey]: (Number(freshPoints[spinCountKey] ?? spinsUsed) || 0) + 1,
      };
      const baseWheelTotal = DAILY_SPINS_MAX + (Number(freshPoints[currentPlayer+"_bonusSpins"]) || 0);
      updatedPoints = withBoostResetStamp(updatedPoints, currentPlayer, "wheel", baseWheelTotal - updatedPoints[spinCountKey]);

      setPoints(updatedPoints);
      await storeSet("points", updatedPoints);
      setSpinResult({ seg, wager, payout, net });
      bbHaptic(net >= 0 ? [20, 45, 25] : 28);
      setSpinning(false);
      setSpinStartPoints(null);
    }, 3000);
  };

const placeBet = async (chosenLine) => {
  bbHaptic(14);
  const safePropWager = clampWager(propWager, 25);
  if (!selectedProp || !propSide || safePropWager < 1 || myPoints < safePropWager) return;

  const card = props.find(p => p.id === selectedProp);
  if (!card) return;

  const lineIdx = lineIndexByProp[selectedProp] ?? Math.floor(card.lineOptions.length / 2);
  const current = card.lineOptions[lineIdx];
  const line = chosenLine ?? current.line;
  const odds = getPropOddsForSide(card, current, lineIdx, propSide);
  const payout = calcPayout(safePropWager, odds.decimal);

  const bet = {
    id: Date.now().toString(),
    bettorId: currentPlayer,
    playerId: card.playerId,
    playerName: card.playerName,
    field: card.field,
    fieldLabel: card.fieldLabel || card.field,
    line,
    side: propSide,
    wager: safePropWager,
    payout,
    odds: odds.american,
    oddsBoosted: !!odds.boosted,
    oddsBoostRate: odds.boosted ? DAILY_ODDS_BOOST_RATE : null,
    status: "open",
    placedAt: new Date().toISOString(),
    settleAt: nextTenAmIso(),
    targetMode: card.mode || "3v3",
    targetText: card.targetText || `next logged ${card.mode || "3v3"} game`,
    duoIds: card.duoIds || null,
    duoLabel: card.duoLabel || "",
    combined: !!card.combined,
    statKeysAtPlacement: getBetSeenGameKeysForPlacement(stats, {
      playerId: card.playerId,
      targetMode: card.mode || "3v3",
      duoIds: card.duoIds || null,
      combined: !!card.combined,
    }),
  };

  // close the sticky wager tray immediately after tapping place bet
  setSelectedProp(null);
  setPropSide(null);
  setPropWager(25);

  const newPts = myPoints - safePropWager;
  const upd = { ...points, [currentPlayer]: newPts };
  setPoints(upd);
  await storeSet("points", upd);

  const updBets = [...(bets || []), bet];
  setBets(updBets);
  await storeSet("bets", updBets);
  await notifyPropBetPlacedPush(bet);

  await pushActivity({
    to: card.playerId,
    type: "prop",
    fromName: PLAYERS.find(p => p.id === currentPlayer)?.name || "someone",
    text: `sent you ${card.mode || "3v3"} props`,
    message: `${propSide.toUpperCase()} ${line} ${card.fieldLabel || card.field} to win ${payout} pts`
  });

};

